export const validateApiKey = async (rawKey: string, preferredModel?: string): Promise<{ isValid: boolean, latency: number, errorType?: 'invalid' | 'quota_exceeded' | 'unknown', activeModel?: string }> => {
    const key = rawKey ? rawKey.trim().replace(/^["']|["']$/g, '') : "";

    if (!key) {
        return { isValid: false, latency: 0, errorType: 'invalid' };
    }

    // LIST OF CANDIDATES TO PROBE
    // The order matters: we prefer newer/faster models, but fallback to older/stable ones.
    const probeModels = [
        "gemini-1.5-flash",          // 1. Standard Alias
        "gemini-1.5-flash-8b",       // 2. New Lightweight (High compatibility)
        "gemini-1.5-flash-001",      // 3. Explicit Version 001
        "gemini-1.5-flash-002",      // 4. Explicit Version 002
        "gemini-1.5-pro",            // 5. Pro Alias
        "gemini-1.0-pro"             // 6. Legacy Backup (Rock solid for old keys)
    ];

    if (preferredModel && !probeModels.includes(preferredModel)) {
        probeModels.unshift(preferredModel);
    }

    const ai = new GoogleGenAI({ apiKey: key });

    // We iterate until we find ONE that works.
    for (const modelId of probeModels) {
        const start = performance.now();
        try {
            // Simple generation to test connectivity and permission
            await ai.models.generateContent({
                model: modelId,
                contents: { parts: [{ text: "Test" }] }, 
            });
            const end = performance.now();

            console.log(`[ISO-AUDIT] SUCCESS: Key works with ${modelId}`);
            return { isValid: true, latency: Math.round(end - start), activeModel: modelId };

        } catch (error: any) {
            const msg = (error.message || "").toLowerCase();
            const status = error.status || 0;

            // Console log to help debugging
            console.warn(`[ISO-AUDIT] Probe failed for ${modelId}: ${status} - ${msg}`);

            // If key is totally invalid, stop probing immediately
            if (msg.includes("api key not valid") || (status === 400 && msg.includes("key"))) {
                return { isValid: false, latency: 0, errorType: 'invalid' };
            }

            // For other errors (404 Not Found, 403 Permission Denied for THIS model), 
            // we continue to the next model in the list.
        }
    }

    // If loop finishes without success
    return { isValid: false, latency: 0, errorType: 'unknown' };
};

