import { GoogleGenAI, Type } from "@google/genai";
import { DEFAULT_GEMINI_MODEL, DEFAULT_VISION_MODEL, MODEL_HIERARCHY, MY_FIXED_KEYS } from "../constants";
import { cleanAndParseJSON } from "../utils";

const getAiClient = (overrideKey?: string) => {
    let keyToUse = overrideKey;

    // Prioritize passed key, then Fixed Keys (Env), then LocalStorage
    if (!keyToUse && MY_FIXED_KEYS.length > 0) {
        keyToUse = MY_FIXED_KEYS[0];
    }

    if (!keyToUse) {
        try {
            // @ts-ignore
            if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env.VITE_API_KEY) {
                // @ts-ignore
                keyToUse = import.meta.env.VITE_API_KEY;
            }
        } catch (e) {}
    }

    if (!keyToUse && typeof process !== 'undefined' && process.env) {
        keyToUse = process.env.API_KEY;
    }

    if (!keyToUse) {
        keyToUse = localStorage.getItem("iso_api_key") || "";
    }

    const apiKey = (keyToUse || "").trim();

    if (!apiKey) {
        // Don't throw here, allow the caller to handle empty key gracefully or UI to prompt
        return null;
    }
    return new GoogleGenAI({ apiKey });
};

// --- REAL VALIDATION ---
export const validateApiKey = async (rawKey: string, preferredModel?: string): Promise<{ isValid: boolean, latency: number, errorType?: 'invalid' | 'quota_exceeded' | 'unknown', activeModel?: string }> => {
    const key = rawKey ? rawKey.trim().replace(/^["']|["']$/g, '') : "";

    if (!key) {
        return { isValid: false, latency: 0, errorType: 'invalid' };
    }

    const ai = new GoogleGenAI({ apiKey: key });

    // Probe List: Prioritize Flash for speed/cost in production
    const probeModels = [
        "gemini-1.5-flash",
        "gemini-1.5-pro",
        "gemini-1.0-pro"
    ];

    if (preferredModel && !probeModels.includes(preferredModel)) {
        probeModels.unshift(preferredModel);
    }

    // Iterate until we find a working model
    for (const modelId of probeModels) {
        const start = performance.now();
        try {
            // Minimal token request to verify connectivity
            await ai.models.generateContent({
                model: modelId,
                contents: { parts: [{ text: "Hi" }] }, 
            });
            const end = performance.now();

            // If we get here, the key is valid for this model
            return { isValid: true, latency: Math.round(end - start), activeModel: modelId };

        } catch (error: any) {
            const msg = (error.message || "").toLowerCase();
            const status = error.status || 0;

            // Hard failure conditions
            if (msg.includes("api key not valid") || status === 400 || msg.includes("invalid argument")) {
                return { isValid: false, latency: 0, errorType: 'invalid' };
            }
            if (status === 429 || msg.includes("quota") || msg.includes("exhausted")) {
                // Continue checking other models? Usually quota is per project, so return failure immediately
                return { isValid: false, latency: 0, errorType: 'quota_exceeded' };
            }
            // For 404 (Model not found) or 403 (Model access denied), continue loop to next model
        }
    }

    // If loop finishes without success
    return { isValid: false, latency: 0, errorType: 'unknown' };
};

