    const ai = getAiClient(apiKey);
    if (!ai) throw new Error("API Key missing");

    const targetModel = model || DEFAULT_VISION_MODEL;

    try {
        const response = await ai.models.generateContent({
            model: targetModel,
            contents: {
                parts: [
                    { text: textPrompt }, 
                    { inlineData: { mimeType, data: base64Data } }
