import React, { useState, useEffect, useRef } from 'react';
import { Icon, IconSelect, IconInput, Modal } from './UI';
import { StandardsData, AuditInfo, Clause, Group, Standard } from '../types';
import { useDebounce, copyToClipboard, cleanAndParseJSON } from '../utils';
import { AUDIT_TYPES, STANDARDS_DATA } from '../constants';
import { generateMissingDescriptions } from '../services/geminiService';

interface SidebarProps {
    isOpen: boolean;
    width: number;
    setWidth: (w: number) => void;
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (k: string) => void;
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;
    onAddNewStandard: () => void;
    onUpdateStandard: (std: Standard) => void;
    onResetStandard: (key: string) => void;
    onReferenceClause: (clause: Clause) => void;
    showIntegrityModal: boolean;
    setShowIntegrityModal: (show: boolean) => void;
    knowledgeFileName: string | null;
    onKnowledgeUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, width, setWidth, standards, standardKey, setStandardKey, auditInfo, setAuditInfo, selectedClauses, setSelectedClauses, onAddNewStandard, onUpdateStandard, onResetStandard, onReferenceClause, showIntegrityModal, setShowIntegrityModal, knowledgeFileName, onKnowledgeUpload }) => {
    const sidebarRef = useRef<HTMLDivElement>(null);
    const scrollContainerRef = useRef<HTMLDivElement>(null); 
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [isResizing, setIsResizing] = useState(false);
    const [searchQueryRaw, setSearchQueryRaw] = useState("");
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);

    // UI State: Scroll-aware Header Visibility
    const [isHeaderVisible, setIsHeaderVisible] = useState(true);
    // UI State: Manual Toggle for Audit Mission
    const [isMissionExpanded, setIsMissionExpanded] = useState(true);

    // Auto-repair states
    const [isRepairing, setIsRepairing] = useState(false);
    const [copiedClauseId, setCopiedClauseId] = useState<string | null>(null);
    const [repairStats, setRepairStats] = useState<{ fixed: number, cleaned: number } | null>(null);
    const [repairedIds, setRepairedIds] = useState<string[]>([]);

    const searchQuery = useDebounce(searchQueryRaw, 300);

    const startResizing = (e: React.MouseEvent) => {
        if ((e.target as Element).classList.contains('resize-handle')) {
            e.preventDefault();
            setIsResizing(true);
            document.body.style.cursor = 'col-resize';
            document.body.style.userSelect = 'none'; 
        }
    };

    useEffect(() => {
        const stopResizing = () => {
            if (isResizing) {
                setIsResizing(false);
                document.body.style.cursor = '';
                document.body.style.userSelect = '';

                if (sidebarRef.current) {
                    const finalWidth = parseInt(sidebarRef.current.style.width, 10);
                    if (!isNaN(finalWidth)) {
                        setWidth(finalWidth);
                    }
                }
            }
        };

        const resize = (e: MouseEvent) => {
            if (isResizing && sidebarRef.current) {
                const MIN_SIDEBAR_WIDTH = 390; 
                const MIN_MAIN_CONTENT_WIDTH = 375; 
                const MAX_SIDEBAR_LIMIT = 800;

                const maxSidebarWidth = Math.min(MAX_SIDEBAR_LIMIT, window.innerWidth - MIN_MAIN_CONTENT_WIDTH);
                const newWidth = Math.max(MIN_SIDEBAR_WIDTH, Math.min(e.clientX, maxSidebarWidth));

                sidebarRef.current.style.width = `${newWidth}px`;
            }
        };

        if (isResizing) {
            window.addEventListener('mousemove', resize);
            window.addEventListener('mouseup', stopResizing);
        }
        return () => {
            window.removeEventListener('mousemove', resize);
            window.removeEventListener('mouseup', stopResizing);
        };
    }, [isResizing, setWidth]);

    const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
        if (isResizing) return;
        const target = e.currentTarget;
        const scrollTop = target.scrollTop;
        const SCROLL_THRESHOLD = 50; 

        if (scrollTop > SCROLL_THRESHOLD && isHeaderVisible) {
            setIsHeaderVisible(false);
        } else if (scrollTop <= SCROLL_THRESHOLD && !isHeaderVisible) {
            setIsHeaderVisible(true);
        }
    };

    useEffect(() => {
        if (scrollContainerRef.current) scrollContainerRef.current.scrollTop = 0;
    }, [standardKey]);

    const runHealthCheck = () => {
        if (!standardKey || !standards[standardKey]) return { isHealthy: false, score: 0, integrity: [], completeness: [] };
        const data = standards[standardKey];
        const integrity: { label: string, status: 'pass' | 'fail', detail: string }[] = [];
        const completeness: { label: string, status: 'pass' | 'fail', detail: string }[] = [];

        const allClauses = data.groups.flatMap(g => g.clauses);
        const flatten = (list: Clause[]): Clause[] => {
            return list.reduce((acc, c) => {
                acc.push(c);
                if (c.subClauses) acc.push(...flatten(c.subClauses));
                return acc;
            }, [] as Clause[]);
        };
        const flatList = flatten(allClauses);

        const missingDesc = flatList.filter(c => !c.description || c.description.trim().length < 2).length;
        integrity.push({ 
            label: 'Content Quality', 
            status: missingDesc === 0 ? 'pass' : 'fail', 
            detail: missingDesc === 0 ? 'Descriptions OK' : `${missingDesc} incomplete` 
        });

        const uniqueCodes = new Set(flatList.map(c => c.code));
        const duplicateCount = flatList.length - uniqueCodes.size;
        integrity.push({ 
            label: 'Data Cleanliness', 
            status: duplicateCount === 0 ? 'pass' : 'fail', 
            detail: duplicateCount === 0 ? 'Clean' : `${duplicateCount} Duplicates` 
        });

        if (standardKey.includes("9001")) {
            const crucial = ['8.4', '8.6', '8.7', '7.1.4'];
            crucial.forEach(code => {
                const found = flatList.some(c => c.code === code);
                completeness.push({ 
                    label: `Clause ${code}`, 
                    status: found ? 'pass' : 'fail', 
                    detail: found ? 'Present' : 'Missing (Required)' 
                });
            });
        }

        if (standardKey.includes("27001")) {
            const annexItems = flatList.filter(c => c.code.startsWith("A."));
            const isFullSet = annexItems.length >= 90; 
            completeness.push({ 
                label: 'Annex A Controls', 
                status: isFullSet ? 'pass' : 'fail', 
                detail: isFullSet ? `${annexItems.length} Controls (OK)` : `${annexItems.length}/93 (Incomplete)` 
            });
        }

        const integrityPass = integrity.every(i => i.status === 'pass');
        const completenessPass = completeness.every(i => i.status === 'pass');
        const isHealthy = integrityPass && completenessPass;

        const totalItems = integrity.length + completeness.length;
        const passItems = integrity.filter(i => i.status === 'pass').length + completeness.filter(i => i.status === 'pass').length;
        const score = Math.round((passItems / (totalItems || 1)) * 100);

        return { isHealthy, score, integrity, completeness };
    };

    const handleAutoRepair = async () => {
        if (!standardKey || !standards[standardKey]) return;
        setIsRepairing(true);
        setRepairStats(null);
        try {
            const currentStandard = JSON.parse(JSON.stringify(standards[standardKey])) as Standard; 
            const missingClauses: {ref: Clause, code: string, title: string}[] = [];
            const fixedIds: string[] = [];
            let duplicateRemovedCount = 0;

            const findMissing = (list: Clause[]) => {
                list.forEach(c => {
                    if (!c.description || c.description.trim().length < 5) {
                        missingClauses.push({ ref: c, code: c.code, title: c.title });
                    }
                    if (c.subClauses) findMissing(c.subClauses);
                });
            };
            currentStandard.groups.forEach((g: Group) => findMissing(g.clauses));

            if (missingClauses.length > 0) {
                const targets = missingClauses.map(i => ({ code: i.code, title: i.title }));
                const jsonStr = await generateMissingDescriptions(targets);
                const descriptions = cleanAndParseJSON(jsonStr);

                if (Array.isArray(descriptions)) {
                    const descMap = descriptions.reduce((acc: any, item: any) => {
                        if(item.code && item.description) acc[item.code] = item.description;
                        return acc;
                    }, {});

                    missingClauses.forEach(item => {
                        if (descMap[item.code]) {
                            item.ref.description = descMap[item.code];
                            fixedIds.push(item.ref.id);
                        }
                    });
                } else if (descriptions && typeof descriptions === 'object') {
                    missingClauses.forEach(item => {
                        if (descriptions[item.code]) {
                            item.ref.description = descriptions[item.code];
                            fixedIds.push(item.ref.id);
                        }
                    });
                }
            }

            const cleanClauses = (clauses: Clause[]): Clause[] => {
                const seenCodes = new Set<string>();
                const unique: Clause[] = [];
                for (const c of clauses) {
                    if (!seenCodes.has(c.code)) {
                        seenCodes.add(c.code);
                        if (c.subClauses) {
                            c.subClauses = cleanClauses(c.subClauses);
                        }
                        unique.push(c);
                    } else {
                        duplicateRemovedCount++;
                    }
                }
                return unique;
            };

            currentStandard.groups.forEach(g => {
                g.clauses = cleanClauses(g.clauses);
            });

            onUpdateStandard(currentStandard);
            setRepairedIds(fixedIds);
            setRepairStats({ fixed: fixedIds.length, cleaned: duplicateRemovedCount });

        } catch (e) {
            console.error("Repair failed", e);
            alert("Failed to repair automatically.");
        } finally {
            setIsRepairing(false);
        }
    };

    const handleCopySelectedClauses = () => {
        if (!standardKey || !standards[standardKey]) return;
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { 
                if (c.id === id) return c; 
                if (c.subClauses) { 
                    const f = findClause(id, c.subClauses); 
                    if (f) return f; 
                } 
            }
        };
        const allClauses = standards[standardKey].groups.flatMap(g => g.clauses);
        const selectedData = selectedClauses
            .map(id => findClause(id, allClauses))
            .filter((c): c is Clause => !!c)
            .map(c => `[${c.code}] ${c.title}`)
            .join('\n');
        copyToClipboard(selectedData);
    };

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    const toggleClauseSelection = (clause: Clause) => {
        const getAllIds = (c: Clause): string[] => {
            let ids = [c.id];
            if (c.subClauses) c.subClauses.forEach(sub => ids.push(...getAllIds(sub)));
            return ids;
        };
        const targetIds = getAllIds(clause);
        const allSelected = targetIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !targetIds.includes(id)) : Array.from(new Set([...prev, ...targetIds])));
    };

    const toggleGroupSelection = (group: Group) => {
        const getAllIds = (list: Clause[]): string[] => {
            let ids: string[] = [];
            list.forEach(c => {
                ids.push(c.id);
                if (c.subClauses) ids.push(...getAllIds(c.subClauses));
            });
            return ids;
        };
        const groupIds = getAllIds(group.clauses);
        const allSelected = groupIds.every(id => selectedClauses.includes(id));

        if (allSelected) {
            setSelectedClauses(prev => prev.filter(id => !groupIds.includes(id)));
        } else {
            setSelectedClauses(prev => [...new Set([...prev, ...groupIds])]);
        }
    };

    const allGroupIds = standards[standardKey]?.groups.map(g => g.id) || [];
    const areAllGroupsExpanded = allGroupIds.length > 0 && expandedGroups.length === allGroupIds.length;

    const toggleExpandAll = () => {
        if (areAllGroupsExpanded) {
            setExpandedGroups([]);
        } else {
            setExpandedGroups(allGroupIds);
        }
    };

    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id) || !!searchQuery;
        const isSelected = selectedClauses.includes(c.id);
        const getChildSelectionStatus = (item: Clause): { all: boolean, some: boolean } => {
            if (!item.subClauses) return { all: selectedClauses.includes(item.id), some: selectedClauses.includes(item.id) };
            const subRes = item.subClauses.map(getChildSelectionStatus);
            const all = selectedClauses.includes(item.id) && subRes.every(r => r.all);
            const some = selectedClauses.includes(item.id) || subRes.some(r => r.some);
            return { all, some };
        };
        const selection = getChildSelectionStatus(c);
        const isCopied = copiedClauseId === c.id;
        const isRepaired = repairedIds.includes(c.id);

        return (
            <div key={c.id} className={`flex flex-col transition-all duration-300 ${level > 0 ? 'ml-4 border-l-2 dark:border-slate-800' : ''}`}>
                <div className={`group flex items-start gap-3 p-2 rounded-xl transition-all duration-200 ease-soft cursor-pointer ${isSelected ? 'bg-indigo-50/80 dark:bg-indigo-900/30 translate-x-1' : isRepaired ? 'bg-emerald-50/80 dark:bg-emerald-900/20 ring-1 ring-emerald-500/30' : 'hover:bg-gray-100/50 dark:hover:bg-slate-800/50 hover:translate-x-1 hover:shadow-sm'}`}>
                    <button onClick={(e) => { e.stopPropagation(); toggleClauseSelection(c); }} className={`mt-1 flex-shrink-0 transition-colors duration-200 ${selection.some ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-gray-300 dark:text-slate-600 hover:text-gray-400'}`}>
                        {selection.all ? <Icon name="CheckSquare" size={16}/> : selection.some ? <div className="w-4 h-4 bg-indigo-500 rounded flex items-center justify-center"><div className="w-2.5 h-0.5 bg-white"></div></div> : <Icon name="Square" size={16}/>}
                    </button>
                    <div 
                        className="flex-1 min-w-0" 
                        onClick={() => hasSubs ? toggleClauseExpand(c.id) : toggleClauseSelection(c)}
                    >
                        <div className="flex items-start justify-between gap-1.5">
                            <div className="flex items-center gap-1.5 flex-wrap">
                                <span className="text-xs font-bold text-indigo-700 dark:text-indigo-400 uppercase shrink-0 bg-indigo-50 dark:bg-indigo-900/30 px-1 rounded">{c.code}</span>
                                <span className="text-sm text-slate-900 dark:text-slate-100 font-medium tracking-tight leading-tight group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{c.title}</span>
                                {isRepaired && <span className="text-[9px] font-black bg-emerald-100 text-emerald-600 px-1.5 py-0.5 rounded-md animate-pulse">UPDATED</span>}
                            </div>
                            <div className="flex items-center gap-1">
                                <button onClick={(e) => { e.stopPropagation(); onReferenceClause(c); }} className="p-1 transition-all transform duration-300 opacity-0 group-hover:opacity-100 text-gray-300 hover:text-cyan-500 dark:hover:text-cyan-400 hover:scale-110" title="Reference original text">
                                    <Icon name="BookOpen" size={14} />
                                </button>
                                <button
                                    onClick={(e) => handleSingleClauseCopy(e, c)}
                                    className={`p-1 transition-all transform duration-300 ${isCopied ? 'text-emerald-500 scale-125 opacity-100' : 'opacity-0 group-hover:opacity-100 text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 hover:scale-110'}`}
                                    title={isCopied ? "Copied!" : "Copy Clause"}
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={isCopied ? 20 : 14} />
                                </button>
                                {hasSubs && <Icon name="ChevronDown" size={12} className={`text-gray-400 mt-0.5 shrink-0 transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}/>}
                            </div>
                        </div>
                        <div className="text-xs text-slate-500 dark:text-slate-400 italic mt-1.5 leading-relaxed block w-full whitespace-normal border-t border-gray-100 dark:border-slate-800 pt-1">
                            {c.description}
                        </div>
                    </div>
                </div>
                {/* Smooth Accordion Animation using Grid */}
                <div className={`grid transition-all duration-300 ease-in-out ${hasSubs && isExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                    <div className="overflow-hidden">
                        {hasSubs && <div className="mt-1 flex flex-col">{c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}</div>}
                    </div>
                </div>
            </div>
        );
    };

    const renderClauses = () => {
        if (!standardKey || !standards[standardKey]) return <div className="text-center text-gray-400 mt-20 italic text-xs uppercase tracking-widest opacity-50">Select a Standard</div>;
        const data = standards[standardKey];

        const getGroupColorClass = (title: string) => {
            const t = title.toUpperCase();
            if (t.includes('PLAN')) return 'bg-blue-600 dark:bg-blue-500 shadow-blue-500/20';
            if (t.includes('SUPPORT')) return 'bg-purple-600 dark:bg-purple-500 shadow-purple-500/20';
            if (t.includes('DO')) return 'bg-orange-600 dark:bg-orange-500 shadow-orange-500/20';
            if (t.includes('CHECK') || t.includes('ACT')) return 'bg-emerald-600 dark:bg-emerald-500 shadow-emerald-500/20';
            if (t.includes('ANNEX')) return 'bg-rose-600 dark:bg-rose-500 shadow-rose-500/20';
            return 'bg-slate-800 dark:bg-slate-700';
        };

        return data.groups.map(g => {
            const isGroupExpanded = expandedGroups.includes(g.id) || !!searchQuery;
            const matchesSearch = (c: Clause): boolean => {
                const term = searchQuery.toLowerCase();
                return c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term) || c.description.toLowerCase().includes(term) || (c.subClauses ? c.subClauses.some(matchesSearch) : false);
            };
            const filteredClauses = searchQuery ? g.clauses.filter(matchesSearch) : g.clauses;
            if (filteredClauses.length === 0) return null;

            return (
                <div key={g.id} className="mb-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-transparent dark:shadow-[0_4px_6px_-1px_rgba(0,0,0,0.3),0_0_0_1px_rgba(255,255,255,0.05)] shadow-sm overflow-hidden transition-all duration-300 hover:shadow-md">
                    <div className="flex items-center justify-between p-3.5 bg-gray-50/50 dark:bg-slate-800/30 cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors" onClick={() => toggleGroupExpand(g.id)}>
                        <div className="flex items-center gap-3">
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleGroupSelection(g); }}
                                className={`p-2 rounded-xl shadow-lg text-white ${getGroupColorClass(g.title)} hover:scale-110 active:scale-95 transition-transform duration-300`}
                                title="Click to Select/Deselect All in Group"
                            >
                                <Icon name={g.icon} size={14}/>
                            </button>
                            <h4 className="text-xs font-black text-slate-900 dark:text-white uppercase tracking-widest">{g.title}</h4>
                        </div>
                        <Icon name="ChevronDown" size={12} className={`text-slate-400 transition-transform duration-300 ${isGroupExpanded ? 'rotate-180' : ''}`}/>
                    </div>
                    <div className={`grid transition-all duration-300 ease-in-out ${isGroupExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                        <div className="overflow-hidden bg-white dark:bg-slate-900">
                             <div className="p-2 space-y-1">{filteredClauses.map(c => renderClauseItem(c))}</div>
                        </div>
                    </div>
                </div>
            );
        });
    };

    const auditFieldIconColor = "text-indigo-700 dark:text-indigo-400";
    const health = runHealthCheck();
    const isCustomStandard = !STANDARDS_DATA[standardKey] || (standards[standardKey] && standards[standardKey] !== STANDARDS_DATA[standardKey]);

    const standardOptions = (() => {
        const rawOptions = Object.keys(standards).map(k => ({ value: k, label: standards[k].name }));
        const seen = new Set();
        const unique = rawOptions.filter(item => {
            const duplicate = seen.has(item.label);
            seen.add(item.label);
            return !duplicate;
        });
        return [...unique, {value: "ADD_NEW", label: "+ Add New Standard..."}];
    })();

    // Workflow Completion Calculation
    const infoCompletion = (() => {
        let score = 0;
        if (standardKey) score++;
        if (auditInfo.type) score++;
        if (auditInfo.company) score++;
        if (auditInfo.auditor) score++;
        return Math.min(4, score); // Max 4 items tracked for progress bar
    })();

    return (
        <div 
            ref={sidebarRef}
            className={`${isOpen ? 'border-r' : 'w-0 border-0 overflow-hidden'} flex flex-col bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 shadow-2xl z-50 relative shrink-0 ${isResizing ? 'transition-none' : 'transition-[width] duration-300 ease-soft'} h-full dark:shadow-[5px_0_15px_-3px_rgba(0,0,0,0.5)]`} 
            style={{ width: isOpen ? (window.innerWidth < 768 ? '100%' : width) : 0 }}
        >
             {isOpen && <div className="absolute right-0 top-0 bottom-0 w-1.5 cursor-col-resize hover:bg-indigo-500 transition-colors z-50 group resize-handle hidden md:block" onMouseDown={startResizing} />}

            {/* --- REFACTORED: AUDIT MISSION CHARTER --- */}
            <div className={`flex-shrink-0 bg-white dark:bg-slate-900 w-full md:min-w-[390px] flex flex-col transition-all duration-400 ease-soft overflow-hidden will-change-auto ${isHeaderVisible ? 'max-h-[1000px] opacity-100 p-5 border-b border-gray-100 dark:border-slate-800' : 'max-h-0 opacity-0 p-0 border-none'}`}>

                {/* Header: Audit Mission - TOGGLEABLE */}
                <div 
                    className="flex items-center justify-between mb-3 cursor-pointer group select-none"
                    onClick={() => setIsMissionExpanded(!isMissionExpanded)}
                    title={isMissionExpanded ? "Collapse Mission Charter" : "Expand Mission Charter"}
                >
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 group-hover:text-indigo-500 transition-colors">
                        <Icon name="Session8_Flag" size={14} className="text-indigo-500"/>
                        Audit Mission Charter
                        <Icon name="ChevronDown" size={12} className={`transition-transform duration-300 text-slate-300 group-hover:text-indigo-400 ${isMissionExpanded ? 'rotate-180' : ''}`}/>
                    </h3>
                    <div className="flex gap-2" onClick={(e) => e.stopPropagation()}>
                        <div className="flex gap-0.5 items-center">
                            {[1, 2, 3, 4].map(step => (
                                <div key={step} className={`w-3 h-1 rounded-full ${step <= infoCompletion ? 'bg-indigo-500' : 'bg-gray-200 dark:bg-slate-700'}`}></div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Setup Card - COLLAPSIBLE CONTENT */}
                <div className={`grid transition-all duration-300 ease-in-out ${isMissionExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                    <div className="overflow-hidden">
                        <div className="bg-gray-50/80 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-3 space-y-4">

                            {/* SECTION 1: SCOPE */}
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Scope Definition</label>
                                <div className="relative">
                                    <IconSelect 
                                        icon="Book" 
                                        iconColor={auditFieldIconColor} 
                                        value={standardKey} 
                                        onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} 
                                        options={standardOptions} 
                                        defaultText="Select ISO Standard" 
                                    />
                                    {standardKey && (
                                        <button onClick={() => setShowIntegrityModal(true)} className={`absolute -top-1.5 -right-1.5 p-1 rounded-full shadow-lg transition-all hover:scale-110 active:scale-95 text-white ring-2 ring-white dark:ring-slate-900 ${health.isHealthy ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Integrity Check">
                                            <Icon name={health.isHealthy ? "CheckCircle2" : "AlertCircle"} size={10}/>
                                        </button>
                                    )}
                                </div>

                                {/* INTEGRATED SOURCE MANAGEMENT */}
                                {standardKey && (
                                    <div className="flex items-center gap-2 mt-1 px-1 animate-in fade-in slide-in-from-top-2 duration-300">
                                        <input type="file" ref={fileInputRef} accept=".pdf,.docx,.txt" className="hidden" onChange={onKnowledgeUpload} />

                                        {knowledgeFileName ? (
                                            <div className="flex-1 flex items-center justify-between bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800 rounded-lg p-1.5 px-2 group hover:shadow-sm transition-all">
                                                <div className="flex items-center gap-1.5 min-w-0">
                                                    <div className="p-1 bg-emerald-100 dark:bg-emerald-800 rounded text-emerald-600 dark:text-emerald-300">
                                                        <Icon name="BookOpen" size={12}/>
                                                    </div>
                                                    <span className="text-[10px] font-bold text-emerald-700 dark:text-emerald-300 truncate max-w-[140px]" title={knowledgeFileName}>{knowledgeFileName}</span>
                                                </div>
                                                <button onClick={() => fileInputRef.current?.click()} className="text-[9px] text-emerald-600 hover:text-emerald-800 dark:hover:text-emerald-200 font-bold underline decoration-emerald-300">Change</button>
                                            </div>
                                        ) : (
                                            <button 
                                                onClick={() => fileInputRef.current?.click()} 
                                                className="flex-1 flex items-center justify-center gap-2 py-2 rounded-lg border border-dashed border-gray-300 dark:border-slate-700 bg-white dark:bg-slate-900 hover:border-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/10 transition-colors group relative overflow-hidden"
                                                title={`Upload full text PDF for ${standards[standardKey]?.name || 'this standard'} to improve citation accuracy.`}
                                            >
                                                <div className="absolute inset-0 bg-stripe-pattern opacity-5"></div>
                                                <Icon name="UploadCloud" size={14} className="text-slate-400 group-hover:text-indigo-500 transition-colors"/>
                                                <span className="text-[10px] font-medium text-slate-500 dark:text-slate-400 group-hover:text-indigo-600 dark:group-hover:text-indigo-400">
                                                    Attach Source PDF for <strong>{standards[standardKey]?.name.split(' ')[0]}</strong>
                                                </span>
                                            </button>
                                        )}
                                    </div>
                                )}

                                <IconSelect icon="FileEdit" iconColor={auditFieldIconColor} value={auditInfo.type} onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} options={Object.keys(AUDIT_TYPES).map(key => ({ value: key, label: key }))} defaultText="Select Audit Type" />
                            </div>

                            {/* SEPARATOR */}
                            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

                            {/* SECTION 2: ENTITY DETAILS */}
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Target Entity</label>
                                <div className="grid grid-cols-[1.5fr_1fr] gap-2">
                                    <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />
                                    <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="SMO/ID" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                                </div>
                                <IconInput icon="Users" iconColor={auditFieldIconColor} placeholder="Department / Site" value={auditInfo.department} onChange={(e: any) => setAuditInfo({...auditInfo, department: e.target.value})} />
                            </div>

                            {/* SEPARATOR */}
                            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

                            {/* SECTION 3: PERSONNEL */}
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Personnel</label>
                                <div className="grid grid-cols-2 gap-2">
                                     <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                                     <IconInput icon="User" iconColor={auditFieldIconColor} placeholder="Interviewee" value={auditInfo.interviewee} onChange={(e: any) => setAuditInfo({...auditInfo, interviewee: e.target.value})} />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 flex flex-col min-h-0 bg-gray-50/40 dark:bg-slate-950/40 w-full md:min-w-[390px]">
                <div className={`p-3 border-b border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10 sticky top-0 transition-all duration-500 ${!isHeaderVisible ? 'shadow-md border-indigo-100 dark:border-indigo-900/50' : ''}`}>
                    <div className="flex items-center gap-2">
                        <div className="relative flex-1 flex items-center gap-1 bg-gray-100 dark:bg-slate-950 rounded-xl px-2 transition-all focus-within:ring-2 focus-within:ring-indigo-500/20 dark:shadow-[inset_0_1px_3px_rgba(0,0,0,0.5)]">
                            <span className="text-blue-700 dark:text-blue-400 font-bold pl-1"><Icon name="Search" size={14}/></span>
                            <input className="w-full bg-transparent py-2 px-1 text-xs font-medium outline-none text-slate-800 dark:text-slate-200 placeholder-gray-400" placeholder="Search clauses..." value={searchQueryRaw} onChange={e => setSearchQueryRaw(e.target.value)}/>

                            <button 
                                onClick={toggleExpandAll} 
                                className="p-1.5 rounded-lg hover:bg-white dark:hover:bg-slate-700 text-slate-400 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors"
                                title={areAllGroupsExpanded ? "Collapse All Groups" : "Expand All Groups"}
                            >
                                <Icon name={areAllGroupsExpanded ? "CollapsePanel" : "ExpandPanel"} size={14}/>
                            </button>
                        </div>

                        {selectedClauses.length > 0 && (
                            <div className="flex gap-2 animate-in fade-in slide-in-from-right-5 duration-300">
                                <button onClick={handleCopySelectedClauses} className="p-2 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 hover:bg-indigo-100 transition-colors relative shadow-sm border border-indigo-100 dark:border-indigo-900/30 hover:scale-105" title="Copy Selected Clauses">
                                    <Icon name="Copy" size={16} />
                                </button>
                                <button onClick={() => setSelectedClauses([])} className="p-2 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 hover:bg-red-100 transition-colors relative shadow-sm border border-red-100 dark:border-red-900/30 hover:scale-105" title="Clear All">
                                    <Icon name="Trash2" size={16} />
                                    <div className="absolute -top-1 -right-1 bg-red-600 text-white text-[9px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-white dark:border-slate-900 shadow-sm animate-bounce">{selectedClauses.length}</div>
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                <div 
                    ref={scrollContainerRef}
                    className="flex-1 overflow-y-auto custom-scrollbar p-3 scroll-smooth"
                    onScroll={handleScroll}
                >
                    <div className="min-h-[150vh] flex flex-col">
                        {renderClauses()}
                        <div className="flex-1"></div> {/* Spacer to fill remaining height */}
                    </div>
                </div>
            </div>

            <Modal isOpen={showIntegrityModal} title="Standard Health Index" onClose={() => setShowIntegrityModal(false)}>
                 <div className="space-y-6">
                    <div className="flex items-center gap-5 p-5 rounded-3xl bg-gray-50 dark:bg-slate-800 border border-gray-100 dark:border-slate-700 shadow-inner dark:shadow-[inset_0_2px_6px_rgba(0,0,0,0.4)]">
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center text-white text-2xl font-black shadow-xl ring-4 ring-white dark:ring-slate-700 ${health.score > 90 ? 'bg-gradient-to-br from-emerald-400 to-emerald-600' : 'bg-gradient-to-br from-orange-400 to-orange-600'}`}>
                            {health.score}%
                        </div>
                        <div className="flex-1">
                            <h4 className="font-black text-slate-900 dark:text-slate-100 uppercase tracking-tight">Data Health</h4>
                            <p className="text-xs text-slate-500 dark:text-slate-400 leading-snug mt-1">{health.isHealthy ? 'Excellent! Data is accurate, clean, and complete for professional use.' : 'Standard data is incomplete or contains errors. Please review.'}</p>
                        </div>
                    </div>
                     <div className="space-y-3">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Integrity Checklist</h5>
                        {health.integrity.map((item, idx) => (
                            <div key={idx} className="flex items-center justify-between p-4 bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-2xl shadow-sm dark:shadow-md">
                                <div className="flex items-center gap-4">
                                    <div className={`p-1.5 rounded-full shadow-sm ${item.status === 'pass' ? 'text-emerald-500 bg-emerald-50 dark:bg-emerald-900/20' : 'text-red-500 bg-red-50 dark:bg-red-900/20'}`}>
                                        <Icon name={item.status === 'pass' ? "CheckCircle2" : "AlertCircle"} size={18}/>
                                    </div>
                                    <span className="text-sm font-bold text-slate-700 dark:text-slate-200">{item.label}</span>
                                </div>
                                <span className={`text-[10px] font-black px-3 py-1 rounded-full shadow-sm uppercase ${item.status === 'pass' ? 'text-emerald-700 bg-emerald-100' : 'text-red-700 bg-red-100'}`}>
                                    {item.detail}
                                </span>
                            </div>
                        ))}
                        {health.completeness.map((item, idx) => (
                            <div key={`comp-${idx}`} className="flex items-center justify-between p-4 bg-white dark:bg-slate-900 border border-gray-100 dark:border-slate-800 rounded-2xl shadow-sm dark:shadow-md">
                                <div className="flex items-center gap-4">
                                    <div className={`p-1.5 rounded-full shadow-sm ${item.status === 'pass' ? 'text-emerald-500 bg-emerald-50 dark:bg-emerald-900/20' : 'text-red-500 bg-red-50 dark:bg-red-900/20'}`}>
                                        <Icon name={item.status === 'pass' ? "CheckCircle2" : "AlertCircle"} size={18}/>
                                    </div>
                                    <span className="text-sm font-bold text-slate-700 dark:text-slate-200">{item.label}</span>
                                </div>
                                <span className={`text-[10px] font-black px-3 py-1 rounded-full shadow-sm uppercase ${item.status === 'pass' ? 'text-emerald-700 bg-emerald-100' : 'text-red-700 bg-red-100'}`}>
                                    {item.detail}
                                </span>
                            </div>
                        ))}
                    </div>

                     <div className="mt-6 pt-4 border-t border-gray-100 dark:border-slate-700 flex justify-end gap-3">
                     {isCustomStandard && (
                        <button 
                            onClick={() => {
                                if(confirm("Are you sure? This will remove all AI repairs and revert to the original static data.")) {
                                    onResetStandard(standardKey);
                                    setShowIntegrityModal(false);
                                    setRepairStats(null);
                                    setRepairedIds([]);
                                }
                            }} 
                            className="px-4 py-2 bg-red-50 hover:bg-red-100 text-red-600 dark:bg-red-900/20 dark:hover:bg-red-900/40 dark:text-red-400 rounded-xl font-bold text-xs flex items-center gap-2 transition-all active:scale-95 border border-red-200 dark:border-red-800"
                        >
                            <Icon name="Trash2" size={14}/>
                            Reset to Default
                        </button>
                     )}

                     {repairStats ? (
                         <div className="flex items-center gap-3 animate-in fade-in slide-in-from-right-5">
                            <div className="text-right">
                                <p className="text-[10px] font-bold text-emerald-600 uppercase">Repair Complete</p>
                                <p className="text-xs text-slate-500">Added {repairStats.fixed} items, Cleaned {repairStats.cleaned} dupes.</p>
                            </div>
                            <button onClick={() => setShowIntegrityModal(false)} className="px-4 py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold text-xs shadow-lg shadow-emerald-500/30">
                                Close & Continue
                            </button>
                         </div>
                     ) : !health.isHealthy && (
                         <button 
                            onClick={handleAutoRepair} 
                            disabled={isRepairing}
                            className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-xs flex items-center gap-2 shadow-lg shadow-indigo-500/30 transition-all active:scale-95 disabled:opacity-70 disabled:active:scale-100"
                        >
                            {isRepairing ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Wand2"/>}
                            {isRepairing ? "AI is Fixing..." : "Auto-Repair Issues with AI"}
                        </button>
                     )}
                 </div>
                 </div>
            </Modal>
        </div>
    );
};
export default Sidebar;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { APP_VERSION, STANDARDS_DATA, INITIAL_EVIDENCE, MODEL_HIERARCHY, MY_FIXED_KEYS, BUILD_TIMESTAMP, DEFAULT_AUDIT_INFO } from './constants';
import { StandardsData, AuditInfo, AnalysisResult, Standard, ApiKeyProfile, Clause, FindingsViewMode, SessionSnapshot } from './types';
import { Icon, FontSizeController, Toast, CommandPaletteModal } from './components/UI';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import ReferenceClauseModal from './components/ReferenceClauseModal';
import RecallModal from './components/RecallModal';
import { generateOcrContent, generateAnalysis, generateTextReport, validateApiKey, fetchFullClauseText } from './services/geminiService';
import { cleanAndParseJSON, fileToBase64, cleanFileName, copyToClipboard, extractTextFromPdf } from './utils';

// New Component Imports
import { EvidenceView } from './components/views/EvidenceView';
import { FindingsView } from './components/views/FindingsView';
import { ReportView } from './components/views/ReportView';
import { SettingsModal } from './components/modals/SettingsModal';
import { ExportProgressModal, ExportState } from './components/modals/ExportProgressModal';
import { AddStandardModal } from './components/modals/AddStandardModal';

declare var mammoth: any;

type LayoutMode = 'evidence' | 'findings' | 'report';
type ExportLanguage = 'en' | 'vi';

export interface UploadedFile {
    id: string;
    file: File;
    status: 'pending' | 'processing' | 'success' | 'error';
    error?: string;
    result?: string;
}

export default function App() {
    // -- STATE --
    const [sessionKey, setSessionKey] = useState(Date.now());

    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(420); 
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);
    const [showRecallModal, setShowRecallModal] = useState(false); 
    const [showAddStandardModal, setShowAddStandardModal] = useState(false);

    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');
    const [focusedFindingIndex, setFocusedFindingIndex] = useState<number>(0); 

    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [newKeyInput, setNewKeyInput] = useState("");
    const [newKeyLabel, setNewKeyLabel] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);

    const [isAutoCheckEnabled, setIsAutoCheckEnabled] = useState(false);

    const [editingKeyId, setEditingKeyId] = useState<string | null>(null);
    const [editLabelInput, setEditLabelInput] = useState("");

    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const [lastSavedTime, setLastSavedTime] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false); 

    const isRestoring = useRef(false);
    const isManuallyCleared = useRef(false);

    // KNOWLEDGE BASE (Source Data)
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    const [referenceClauseState, setReferenceClauseState] = useState<{
        isOpen: boolean;
        clause: Clause | null;
        fullText: { en: string; vi: string };
        isLoading: boolean;
    }>({
        isOpen: false,
        clause: null,
        fullText: { en: "", vi: "" },
        isLoading: false,
    });

    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 

    const [reportTemplate, setReportTemplate] = useState<string>("");
    const [templateFileName, setTemplateFileName] = useState<string>("");

    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);

    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);

    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);

    const [exportState, setExportState] = useState<ExportState>({
        isOpen: false,
        isPaused: false,
        isFinished: false,
        totalChunks: 0,
        processedChunksCount: 0,
        chunks: [],
        results: [],
        error: null,
        currentType: 'report',
        targetLang: 'en'
    });

    const [aiError, setAiError] = useState<string | null>(null);
    const [isErrorClosing, setIsErrorClosing] = useState(false);
    const [rescueKey, setRescueKey] = useState("");
    const [isRescuing, setIsRescuing] = useState(false);

    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });

    const tabsList = [
        { id: 'evidence', label: '1. Evidence', icon: 'ScanText', colorClass: 'bg-blue-500', textClass: 'text-blue-600', borderClass: 'border-blue-500', bgSoft: 'bg-blue-50 dark:bg-blue-950/30' }, 
        { id: 'findings', label: '2. Findings', icon: 'Wand2', colorClass: 'bg-purple-500', textClass: 'text-purple-600', borderClass: 'border-purple-500', bgSoft: 'bg-purple-50 dark:bg-purple-950/30' }, 
        { id: 'report', label: '3. Report', icon: 'FileText', colorClass: 'bg-emerald-500', textClass: 'text-emerald-600', borderClass: 'border-emerald-500', bgSoft: 'bg-emerald-50 dark:bg-emerald-950/30' }
    ];

    const currentTabConfig = tabsList.find(t => t.id === layoutMode) || tabsList[0];
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);

    const allStandards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const hasEvidence = evidence.trim().length > 0 || uploadedFiles.length > 0;

    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;
    const isReadyToSynthesize = !isReportLoading && analysisResult && Object.values(selectedFindings).some(v => v);

    const poolStats = useMemo(() => {
        const total = apiKeys.length;
        const valid = apiKeys.filter(k => k.status === 'valid').length;
        return { total, valid };
    }, [apiKeys]);

    const activeKeyProfile = useMemo(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);
    const isSystemHealthy = activeKeyProfile?.status === 'valid';

    // ... (Keep existing loadKeyData, Background Checker, etc. same as before) ...
    const loadKeyData = (): ApiKeyProfile[] => {
        try {
            const stored = localStorage.getItem("iso_api_keys");
            const loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (fixedKey && !existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ id: `fixed_key_${index}_${Math.random().toString(36).substr(2, 5)}`, label: `Environment Key ${index + 1}`, key: fixedKey, status: 'unknown', latency: 0, lastChecked: new Date().toISOString() });
                    hasChanges = true;
                }
            });
            if (hasChanges) localStorage.setItem("iso_api_keys", JSON.stringify(loadedKeys));
            const savedActiveId = localStorage.getItem("iso_active_key_id");
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) setActiveKeyId(savedActiveId);
            else if (loadedKeys.length > 0 && !activeKeyId) setActiveKeyId(loadedKeys[0].id);
            return loadedKeys;
        } catch (e) { console.error("Failed to load keys", e); return []; }
    };

    // --- PERSISTENT KNOWLEDGE BASE STORAGE ---
    const getStorageKey = (stdKey: string) => `iso_kb_content_${stdKey}`;
    const getStorageNameKey = (stdKey: string) => `iso_kb_name_${stdKey}`;

    const loadKnowledgeForStandard = (key: string) => {
        try {
            const savedContent = localStorage.getItem(getStorageKey(key));
            const savedName = localStorage.getItem(getStorageNameKey(key));
            if (savedContent && savedName) {
                setKnowledgeBase(savedContent);
                setKnowledgeFileName(savedName);
                setToastMsg(`Restored source document for ${allStandards[key]?.name || key}`);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) {
            console.error("Failed to load KB", e);
        }
    };

    const saveKnowledgeToStorage = (key: string, content: string, fileName: string) => {
        try {
            localStorage.setItem(getStorageKey(key), content);
            localStorage.setItem(getStorageNameKey(key), fileName);
        } catch (e) {
            console.error("Storage Quota Exceeded for KB", e);
            setToastMsg("Warning: Document too large to save for future sessions (Quota Exceeded). It will work for this session only.");
        }
    };

    // --- CRITICAL: Reset/Restore Knowledge Base when Standard changes ---
    const handleSetStandardKey = (key: string) => {
        if (key !== standardKey) {
            setStandardKey(key);
            // Attempt to load existing KB for this new key
            loadKnowledgeForStandard(key);
        }
    };

    useEffect(() => {
        if (!isAutoCheckEnabled) return;
        const intervalId = setInterval(() => {
            if (!isAnalyzeLoading && !isOcrLoading && !isReportLoading && !isCheckingKey && apiKeys.length > 0) performBackgroundHealthCheck();
        }, 45000); 
        return () => clearInterval(intervalId);
    }, [isAutoCheckEnabled, isAnalyzeLoading, isOcrLoading, isReportLoading, isCheckingKey, apiKeys]);

    const performBackgroundHealthCheck = async () => {
        const sortedKeys = [...apiKeys].sort((a, b) => new Date(a.lastChecked || 0).getTime() - new Date(b.lastChecked || 0).getTime());
        const candidate = sortedKeys[0]; if (!candidate) return;
        setApiKeys(prev => prev.map(k => k.id === candidate.id ? { ...k, status: 'checking' } : k));
        const cap = await determineKeyCapabilities(candidate.key);
        const today = new Date().toISOString().split('T')[0];
        setApiKeys(prev => prev.map(k => k.id === candidate.id ? { ...k, status: cap.status, activeModel: cap.activeModel || k.activeModel, latency: cap.latency, lastChecked: new Date().toISOString(), lastResetDate: today } : k));
    };

    const dismissError = () => { setIsErrorClosing(true); setTimeout(() => { setAiError(null); setIsErrorClosing(false); }, 300); };

    const handleGenericError = (e: any) => {
        const msg = e.message || "Unknown error";
        if (msg.includes("ALL_KEYS_EXHAUSTED")) { setAiError("All API Keys have been exhausted or Quota exceeded."); setShowSettingsModal(true); }
        else if (msg.includes("API Key is missing")) { setToastMsg("API Key is required. Please check settings."); setShowSettingsModal(true); }
        else setAiError(msg);
    };

    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart; const end = textarea.selectionEnd; const currentText = textarea.value;
            const textWithBreaks = `\n${textToInsert.trim()}\n`;
            const newValue = currentText.substring(0, start) + textWithBreaks + currentText.substring(end);
            setEvidence(newValue);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
            setTimeout(() => { if (evidenceTextareaRef.current) { evidenceTextareaRef.current.focus(); evidenceTextareaRef.current.setSelectionRange(start + textWithBreaks.length, start + textWithBreaks.length); } }, 100);
        } else {
            setEvidence(prev => prev + "\n" + textToInsert.trim());
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    const determineKeyCapabilities = async (key: string): Promise<{ status: 'valid' | 'invalid' | 'quota_exceeded' | 'referrer_error' | 'unknown', activeModel?: string, latency: number }> => {
        const result = await validateApiKey(key);
        let status: 'valid' | 'invalid' | 'quota_exceeded' | 'referrer_error' | 'unknown' = 'unknown';
        if (result.isValid) status = 'valid';
        else if (result.errorType === 'network_error') status = 'unknown'; 
        else if (result.errorType) status = result.errorType as any;
        return { status, activeModel: result.activeModel, latency: result.latency };
    };

    const checkAllKeys = async (initialKeys: ApiKeyProfile[]) => {
        setIsCheckingKey(true); 
        setApiKeys(prev => prev.map(k => ({ ...k, status: 'checking' })));
        const today = new Date().toISOString().split('T')[0]; 
        const updatedKeys = [...initialKeys];
        for (let i = 0; i < updatedKeys.length; i++) {
            const profile = updatedKeys[i]; 
            const cap = await determineKeyCapabilities(profile.key);
            updatedKeys[i] = { 
                ...profile, 
                status: cap.status, 
                activeModel: cap.activeModel, 
                latency: cap.latency, 
                lastChecked: new Date().toISOString(), 
                lastResetDate: today 
            };
            setApiKeys(prev => {
                const newArr = [...prev];
                const idx = newArr.findIndex(k => k.id === profile.id);
                if (idx !== -1) newArr[idx] = updatedKeys[i];
                return newArr;
            });
            await new Promise(r => setTimeout(r, 100));
        }
        setApiKeys(currentKeys => {
            const currentActiveProfile = currentKeys.find(k => k.id === activeKeyId);
            if (!currentActiveProfile || (currentActiveProfile.status !== 'valid' && currentActiveProfile.status !== 'unknown')) {
                const bestKey = currentKeys.filter(k => k.status === 'valid').sort((a, b) => a.latency - b.latency)[0];
                if (bestKey) { 
                    setActiveKeyId(bestKey.id); 
                    localStorage.setItem("iso_active_key_id", bestKey.id);
                    setTimeout(() => setToastMsg(`Auto-switched to healthy key: ${bestKey.label}`), 0); 
                } 
            }
            localStorage.setItem("iso_api_keys", JSON.stringify(currentKeys));
            return currentKeys;
        });
        setIsCheckingKey(false);
    };

    const handleRefreshStatus = async (id: string) => {
        const keyProfile = apiKeys.find(k => k.id === id); 
        if (!keyProfile) return;
        setApiKeys(prev => prev.map(k => k.id === id ? { ...k, status: 'checking' } : k));
        const cap = await determineKeyCapabilities(keyProfile.key);
        setApiKeys(prev => {
            const next = prev.map(k => k.id === id ? { 
                ...k, 
                status: cap.status, 
                activeModel: cap.activeModel || k.activeModel, 
                latency: cap.latency, 
                lastChecked: new Date().toISOString() 
            } : k);
            localStorage.setItem("iso_api_keys", JSON.stringify(next));
            return next;
        });
    };

    const handleAddKey = async () => {
        if (!newKeyInput.trim()) return;
        if (apiKeys.some(k => k.key === newKeyInput.trim())) { setToastMsg("This API Key is already in your pool!"); setNewKeyInput(""); return; }
        setIsCheckingKey(true); 
        const tempId = Date.now().toString(); 
        const cap = await determineKeyCapabilities(newKeyInput);
        const newProfile: ApiKeyProfile = { 
            id: tempId, 
            label: newKeyLabel || `Key ${apiKeys.length + 1}`, 
            key: newKeyInput, 
            status: cap.status, 
            activeModel: cap.activeModel, 
            latency: cap.latency, 
            lastChecked: new Date().toISOString(), 
            lastResetDate: new Date().toISOString().split('T')[0] 
        };
        const nextKeys = [...apiKeys, newProfile];
        setApiKeys(nextKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(nextKeys));
        if (apiKeys.length === 0 || (activeKeyProfile?.status !== 'valid' && cap.status === 'valid')) {
            setActiveKeyId(tempId);
            localStorage.setItem("iso_active_key_id", tempId);
        }
        setNewKeyInput(""); setNewKeyLabel(""); setIsCheckingKey(false);
        if(cap.status === 'valid') setToastMsg("Key added successfully!");
        else if (cap.status === 'referrer_error') setAiError("Key restricted! Check 'HTTP Referrers' in Google Cloud Console.");
        else setAiError("The key you added appears invalid or network is blocking it.");
    };

    const handleDeleteKey = (id: string) => {
        const nextKeys = apiKeys.filter(k => k.id !== id);
        let newActiveId = activeKeyId;
        if (activeKeyId === id) {
            const nextBest = nextKeys.find(k => k.status === 'valid') || nextKeys[0];
            newActiveId = nextBest ? nextBest.id : "";
        }
        setApiKeys(nextKeys);
        if (newActiveId !== activeKeyId) setActiveKeyId(newActiveId);
        localStorage.setItem("iso_api_keys", JSON.stringify(nextKeys));
        if (newActiveId) localStorage.setItem("iso_active_key_id", newActiveId);
        else localStorage.removeItem("iso_active_key_id");
        setToastMsg("Key removed from pool.");
    };

    const executeWithSmartFailover = async <T,>(operation: (apiKey: string, model: string) => Promise<T>): Promise<T> => {
        const candidates = apiKeys.filter(k => k.status !== 'invalid').sort((a, b) => {
            if (a.status === 'valid' && b.status !== 'valid') return -1;
            if (a.status !== 'valid' && b.status === 'valid') return 1;
            if (a.id === activeKeyId) return -1;
            if (b.id === activeKeyId) return 1;
            return a.latency - b.latency;
        });
        if (candidates.length === 0) throw new Error("API Key is missing or all keys are invalid.");
        let lastError: any;
        for (const profile of candidates) {
            const modelToUse = profile.activeModel || MODEL_HIERARCHY[0];
            try {
                if (profile.id !== activeKeyId) setActiveKeyId(profile.id);
                const result = await operation(profile.key, modelToUse);
                return result;
            } catch (error: any) {
                console.warn(`Key ${profile.label} failed on ${modelToUse}:`, error); lastError = error;
                const msg = (error.message || "").toLowerCase();
                if (msg.includes("429") || msg.includes("quota") || msg.includes("resource exhausted")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'quota_exceeded' } : k));
                else if (msg.includes("403") || msg.includes("key not valid") || msg.includes("permission denied")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'invalid' } : k));
            }
        }
        throw new Error(lastError?.message || "ALL_KEYS_EXHAUSTED");
    };

    const loadSessionData = () => {
        try {
            const session = localStorage.getItem("iso_session_data");
            const customStds = localStorage.getItem("iso_custom_standards");
            if (customStds) setCustomStandards(JSON.parse(customStds));
            if (session) {
                const data = JSON.parse(session);
                if (data.standardKey) {
                    setStandardKey(data.standardKey);
                    // Also attempt to load knowledge base for this standard
                    loadKnowledgeForStandard(data.standardKey);
                }
                if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
                if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
                if (data.evidence) setEvidence(data.evidence);
                if (data.analysisResult) setAnalysisResult(data.analysisResult);
                if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
                if (data.finalReportText) setFinalReportText(data.finalReportText);
                setLastSavedTime(new Date().toLocaleTimeString());
                setToastMsg("Previous session restored.");
            }
        } catch (e) { console.error("Load failed", e); }
    };

    const handleUpdateStandard = (std: Standard) => { setCustomStandards(prev => ({ ...prev, [standardKey]: std })); setToastMsg("Standard updated successfully."); };
    const handleResetStandard = (key: string) => { setCustomStandards(prev => { const next = { ...prev }; delete next[key]; return next; }); setToastMsg("Standard reset to default."); };

    // --- INTEGRATED SOURCE FILE PROCESSING ---
    const processSourceFile = async (file: File): Promise<string> => {
        let text = "";
        try {
            if (file.name.endsWith('.pdf')) {
                text = await extractTextFromPdf(file);
            } else if (file.name.endsWith('.docx')) {
                if (typeof mammoth === 'undefined') throw new Error("Mammoth library missing");
                const arrayBuffer = await file.arrayBuffer();
                const result = await mammoth.extractRawText({ arrayBuffer });
                text = result.value;
            } else {
                text = await file.text();
            }
            if (!text || text.length < 50) throw new Error("File content is too short or empty.");
            return text;
        } catch (err: any) {
            console.error("File processing error:", err);
            throw new Error(`Failed to parse ${file.name}: ${err.message}`);
        }
    };

    // --- KNOWLEDGE BASE UPLOAD (EXISTING STANDARD) ---
    const handleKnowledgeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; 
        if (!file) return; 

        setKnowledgeFileName(file.name);
        setToastMsg("Parsing Standard Document...");

        try {
            const text = await processSourceFile(file);
            setKnowledgeBase(text);
            setToastMsg(`Standard Loaded (${(text.length / 1024).toFixed(0)}KB). Saving for future use...`);

            // Save to persistent storage
            if (standardKey) {
                saveKnowledgeToStorage(standardKey, text, file.name);
            }
        } catch (err: any) {
            setToastMsg(err.message);
            setKnowledgeFileName(null);
            setKnowledgeBase(null);
        }
    };

    // --- ADD NEW STANDARD (INTEGRATED FLOW) ---
    const handleAddStandard = async (name: string, file: File | null) => {
        setShowAddStandardModal(false);
        const newKey = `CUSTOM_${Date.now()}`;

        // 1. Create Base Structure
        const newStandard: Standard = {
            name: name,
            description: `Custom Standard created on ${new Date().toLocaleDateString()}`,
            groups: [{
                id: `GRP_${Date.now()}`,
                title: "General Requirements",
                icon: "Book",
                clauses: [
                    { id: `CL_${Date.now()}_1`, code: "1", title: "General", description: "Requirement details pending AI extraction." }
                ]
            }]
        };

        // 2. Process File if attached
        if (file) {
            setToastMsg("Processing source document...");
            try {
                const text = await processSourceFile(file);
                setKnowledgeBase(text);
                setKnowledgeFileName(file.name);
                saveKnowledgeToStorage(newKey, text, file.name);
            } catch (err: any) {
                setToastMsg(`Standard created, but file failed: ${err.message}`);
            }
        } else {
            setKnowledgeBase(null);
            setKnowledgeFileName(null);
        }

        // 3. Update State
        setCustomStandards(prev => ({ ...prev, [newKey]: newStandard }));
        setStandardKey(newKey);
        setToastMsg(`Created new standard: ${name}`);
    };

    // ... (Auto Save, BeforeUnload, New Session, Restore, OCR, Export, Analyze, Report - kept same) ...
    // --- ROBUST AUTO-SAVE LOGIC ---
    useEffect(() => {
        if (isRestoring.current) return;
        const isEmptyState = !evidence && (!selectedClauses || selectedClauses.length === 0);
        if (isEmptyState && !isManuallyCleared.current) {
            if (localStorage.getItem("iso_session_data")) {
                return; 
            }
        }
        setIsSaving(true);
        const handler = setTimeout(() => {
            if (isRestoring.current) {
                setIsSaving(false);
                return;
            }
            const sessionData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
            localStorage.setItem("iso_session_data", JSON.stringify(sessionData));
            localStorage.setItem("iso_custom_standards", JSON.stringify(customStandards));
            localStorage.setItem("iso_api_keys", JSON.stringify(apiKeys));
            if (isManuallyCleared.current) isManuallyCleared.current = false;
            const now = new Date();
            setLastSavedTime(now.toLocaleTimeString());
            setIsSaving(false);
        }, 800); 
        return () => clearTimeout(handler);
    }, [standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText, customStandards, apiKeys]);

    useEffect(() => {
        const handleBeforeUnload = (e: BeforeUnloadEvent) => {
            if (!isRestoring.current) {
                const sessionData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
                localStorage.setItem("iso_session_data", JSON.stringify(sessionData));
            }
        };
        window.addEventListener('beforeunload', handleBeforeUnload);
        return () => window.removeEventListener('beforeunload', handleBeforeUnload);
    }, [standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText]);

    const handleNewSession = (e?: any) => { 
        if(e) e.stopPropagation(); 
        if(!confirm("Start New Session? Current data will be moved to 'Backup Vault'.")) return; 
        try {
            const currentData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
            const hasData = evidence.trim().length > 0 || selectedClauses.length > 0;
            if (hasData) {
                const snapshot: SessionSnapshot = {
                    id: `backup_${Date.now()}`,
                    timestamp: Date.now(),
                    label: "Backup (Pre-Reset)",
                    triggerType: "MANUAL_BACKUP",
                    data: currentData
                };
                const historyRaw = localStorage.getItem("iso_session_history");
                const history = historyRaw ? JSON.parse(historyRaw) : [];
                const newHistory = [snapshot, ...history].slice(0, 5);
                localStorage.setItem("iso_session_history", JSON.stringify(newHistory));
            }
            isManuallyCleared.current = true;
            localStorage.removeItem("iso_session_data");
            setStandardKey("");
            setAuditInfo(DEFAULT_AUDIT_INFO); 
            setEvidence(""); 
            setSelectedClauses([]); 
            setUploadedFiles([]); 
            setAnalysisResult(null); 
            setSelectedFindings({}); 
            setFinalReportText(null); 
            setLastSavedTime(null); 
            setSessionKey(Date.now());
            setKnowledgeBase(null); 
            setKnowledgeFileName(null);
            setLayoutMode('evidence'); 
            setToastMsg("New Session Started. (Previous session archived in Recall)");
        } catch (error) {
            console.error("New Session Error", error);
            setToastMsg("Error creating backup. Session reset anyway.");
        }
    };

    const handleRestoreSnapshot = (snapshot: SessionSnapshot) => {
        try {
            isRestoring.current = true;
            setShowRecallModal(false);
            const data = snapshot.data;
            localStorage.setItem("iso_session_data", JSON.stringify(data));
            if (data.standardKey) {
                setStandardKey(data.standardKey);
                loadKnowledgeForStandard(data.standardKey);
            }
            setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...(data.auditInfo || {}) });
            if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
            if (data.evidence !== undefined) setEvidence(data.evidence);
            setUploadedFiles([]); 
            if (data.analysisResult) setAnalysisResult(data.analysisResult);
            if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
            if (data.finalReportText) setFinalReportText(data.finalReportText);
            setSessionKey(Date.now());
            const now = new Date();
            setLastSavedTime(now.toLocaleTimeString());
            setToastMsg(`Restored session from: ${new Date(snapshot.timestamp).toLocaleTimeString()}`);
            setTimeout(() => {
                isRestoring.current = false;
                isManuallyCleared.current = false; 
            }, 1200);
        } catch (e) {
            console.error("Restore failed", e);
            setToastMsg("Failed to restore session snapshot.");
            isRestoring.current = false;
        }
    };

    const handleOcrUpload = async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;
        setIsOcrLoading(true); setLoadingMessage("Processing documents with Vision AI...");
        let processedCount = 0;
        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));
                let text = "";
                if (fileEntry.file.type === 'text/plain') text = await fileEntry.file.text();
                else {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await executeWithSmartFailover(async (key, model) => generateOcrContent("Extract all text.", base64, fileEntry.file.type, key, model));
                }
                if (text) {
                    const separator = `\n\n--- FILE: ${fileEntry.file.name} ---\n`;
                    insertTextAtCursor(separator + text);
                    setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: text } : f));
                    processedCount++;
                } else throw new Error("No text extracted");
            } catch (error: any) {
                console.error("OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsOcrLoading(false); setLoadingMessage(""); setToastMsg(`Processed ${processedCount} files.`);
    };

    const handleTemplateUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file) return; setTemplateFileName(file.name);
        try {
            if (file.name.endsWith('.docx')) {
                if (typeof mammoth === 'undefined') { alert("Mammoth library not loaded for .docx support"); return; }
                const arrayBuffer = await file.arrayBuffer(); const result = await mammoth.extractRawText({ arrayBuffer }); setReportTemplate(result.value);
            } else { const text = await file.text(); setReportTemplate(text); }
            setToastMsg("Template loaded successfully.");
        } catch (err) { setToastMsg("Failed to load template."); console.error(err); }
    };

    const startSmartExport = (content: string, type: 'notes' | 'report' | 'evidence', lang: ExportLanguage) => {
        if (!content) return;
        const CHUNK_SIZE = 4000; const chunks = []; for (let i = 0; i < content.length; i += CHUNK_SIZE) chunks.push(content.substring(i, i + CHUNK_SIZE));
        setExportState({ isOpen: true, isPaused: false, isFinished: false, totalChunks: chunks.length, processedChunksCount: 0, chunks, results: new Array(chunks.length).fill(""), error: null, currentType: type, targetLang: lang });
    };

    const toggleAutoCheck = (enabled: boolean) => { setIsAutoCheckEnabled(enabled); localStorage.setItem('iso_auto_check', String(enabled)); setToastMsg(enabled ? "Auto-health check enabled." : "Auto-health check disabled."); };
    const handleStartEdit = (keyProfile: ApiKeyProfile) => { setEditingKeyId(keyProfile.id); setEditLabelInput(keyProfile.label); };
    const handleSaveLabel = () => { if (editingKeyId) { setApiKeys(prev => prev.map(k => k.id === editingKeyId ? { ...k, label: editLabelInput } : k)); setEditingKeyId(null); } };


    const handleOpenReferenceClause = async (clause: Clause) => {
        setReferenceClauseState({ isOpen: true, clause, isLoading: true, fullText: { en: "", vi: "" } });
        try {
            const text = await executeWithSmartFailover(async (key, model) => fetchFullClauseText(clause, allStandards[standardKey].name, knowledgeBase, key, model));
            setReferenceClauseState(prev => ({ ...prev, isLoading: false, fullText: text }));
        } catch (e: any) {
            setReferenceClauseState({ isOpen: false, clause: null, isLoading: false, fullText: { en: "", vi: "" } });
            setAiError("API Failed during lookup."); setShowSettingsModal(true); 
        }
    };

    const handleInsertReferenceText = (text: string) => {
        if (!referenceClauseState.clause) return;
        const quoteText = `\n--- REFERENCE: [${referenceClauseState.clause.code}] ${referenceClauseState.clause.title} ---\n${text}\n--- END REFERENCE ---\n`.trim();
        insertTextAtCursor(quoteText);
        setReferenceClauseState({ isOpen: false, clause: null, isLoading: false, fullText: { en: "", vi: "" } });
    };

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => { if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); setIsCmdPaletteOpen(prev => !prev); } };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    const commandActions = useMemo(() => {
        const baseActions: any[] = [
            { label: "Analyze Compliance", desc: `Start AI analysis`, icon: "Wand2", shortcut: "AI", action: handleAnalyze },
            { label: "Validate API Key Pool", desc: "Check connection health", icon: "RefreshCw", action: () => { checkAllKeys(apiKeys); setToastMsg("Validating Neural Pool..."); } },
            { label: "Settings", desc: "Manage configuration", icon: "Settings", action: () => setShowSettingsModal(true) },
            { label: "Generate Report", desc: "Synthesize final report", icon: "FileText", action: handleGenerateReport },
            { label: "Toggle Dark Mode", desc: `Switch to ${isDarkMode ? 'Light' : 'Dark'}`, icon: isDarkMode ? "Sun" : "Moon", action: () => setIsDarkMode(!isDarkMode) },
        ];

        // Ensure we have a valid standard selected before adding clause actions
        if (standardKey && allStandards[standardKey]) {
            const flatten = (list: Clause[]): Clause[] => list.reduce((acc, c) => {
                acc.push(c);
                if (c.subClauses) acc.push(...flatten(c.subClauses));
                return acc;
            }, [] as Clause[]);

            const allClauses = flatten(allStandards[standardKey].groups.flatMap(g => g.clauses));

            const clauseActions = allClauses.map(c => ({
                label: `[${c.code}] ${c.title}`,
                desc: c.description || "No description",
                icon: "Session6_Zap", // Use a generic icon or specific if available
                type: 'clause',
                // Action to select/deselect the clause
                action: () => {
                    const isSelected = selectedClauses.includes(c.id);
                    if (isSelected) setSelectedClauses(prev => prev.filter(id => id !== c.id));
                    else setSelectedClauses(prev => [...prev, c.id]);
                    insertTextAtCursor(`[${c.code}] ${c.title}`);
                    setToastMsg(`Inserted clause ${c.code} and ${isSelected ? 'removed from' : 'added to'} audit scope.`);
                    setIsCmdPaletteOpen(false);
                },
                // Action strictly for looking up reference
                onReference: (e: any) => {
                    if (e) e.stopPropagation();
                    handleOpenReferenceClause(c);
                    setIsCmdPaletteOpen(false);
                }
            }));
            return [...baseActions, ...clauseActions];
        }

        return baseActions;
    }, [isDarkMode, standardKey, allStandards, selectedClauses, activeKeyId, apiKeys]); 

    // ... (Badge, Tooltip, and Render logic - kept same) ...
    const displayBadge = useMemo(() => {
        const currentStandardName = allStandards[standardKey]?.name || "";
        const match = currentStandardName.match(/\((.*?)\)/);
        return match ? match[1] : (currentStandardName.split(' ')[0] || 'ISO');
    }, [standardKey, allStandards]);

    const badgeColorClass = useMemo(() => {
        const text = displayBadge.toUpperCase();
        if (text.includes('EMS') || text.includes('14001')) return "bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-700/50";
        if (text.includes('QMS') || text.includes('9001')) return "bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 border-blue-200 dark:border-blue-700/50";
        if (text.includes('ISMS') || text.includes('27001')) return "bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300 border-purple-200 dark:border-purple-700/50";
        return "bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 border-indigo-100 dark:border-indigo-800/50";
    }, [displayBadge]);

    const getAnalyzeTooltip = () => {
        if (isAnalyzeLoading) return "AI is analyzing...";
        const missing = [];
        if (selectedClauses.length === 0) missing.push("Clauses");
        if (!hasEvidence) missing.push("Evidence");
        return missing.length > 0 ? `Missing: ${missing.join(" & ")}` : "Click to Start AI Analysis";
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 ease-soft relative">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}

            {aiError && (
                <div className={`fixed z-[9999] top-20 left-4 right-4 md:left-auto md:right-5 md:w-96 md:max-w-sm bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl rounded-r-xl p-4 animate-shake transition-all duration-300 ${isErrorClosing ? 'opacity-0 translate-x-4' : 'opacity-100 translate-x-0'}`}>
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold"><Icon name="AlertCircle" size={20}/><span>System Alert</span></div>
                        <button onClick={dismissError} className="text-gray-400 hover:text-slate-800 dark:hover:text-white transition-colors p-1 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700"><Icon name="X" size={18}/></button>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed mt-1">{aiError}</p>
                </div>
            )}

            <header className="flex-shrink-0 px-4 md:px-6 py-0 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-[70] relative flex justify-between items-center h-16 transition-all duration-300">
                <div className="flex items-center h-full gap-3 md:gap-5">
                    <div className="relative group cursor-pointer flex items-center justify-center transition-all duration-500 hover:opacity-100 active:scale-95" onClick={() => setIsSidebarOpen(!isSidebarOpen)} title="Toggle Sidebar">
                        <div className="relative w-10 h-10 md:w-14 md:h-14 flex items-center justify-center">
                            <div className="relative z-10">
                                {isSidebarOpen ? <div className="relative w-8 h-8"><div className="absolute inset-0 border-2 border-transparent border-t-indigo-500 border-b-cyan-500 rounded-full animate-infinity-spin drop-shadow-[0_0_8px_rgba(6,182,212,0.8)]"></div><div className="absolute inset-2 border-2 border-transparent border-l-purple-500 border-r-pink-500 rounded-full animate-spin-reverse drop-shadow-[0_0_6px_rgba(236,72,153,0.8)]"></div></div>
                                    : <div className="hover:scale-110 transition-transform duration-300 drop-shadow-[0_0_15px_rgba(0,242,195,0.6)]"><Icon name="TDLogo" size={32} /></div> }
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 md:gap-3">
                        <h1 className="hidden md:block text-lg font-bold tracking-tight text-slate-900 dark:text-white leading-none">ISO Audit <span className="font-light text-slate-400">Pro</span></h1>
                        <div className="flex items-center"><span className={`text-[11px] font-bold px-3 py-1 rounded-full border shadow-sm uppercase tracking-wider backdrop-blur-sm transition-colors duration-300 ${badgeColorClass}`}>{displayBadge}</span></div>
                    </div>
                </div>
                <div className="flex items-center gap-2 md:gap-3">
                    <button onClick={() => setIsCmdPaletteOpen(true)} className="p-2 rounded-xl text-slate-500 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 hover:bg-gray-100 dark:hover:bg-slate-800 transition-all active:scale-95" title="Command Palette (Ctrl+K)">
                        <Icon name="Session6_Zap" size={20}/>
                    </button>
                    <div className="hidden lg:block"><FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(dir: 'increase' | 'decrease') => setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.3) : Math.max(prev - 0.1, 0.8))} /></div>
                    <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-xl text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-slate-800 transition-all"><Icon name={isDarkMode ? "Sun" : "Moon"} size={18}/></button>
                    <button onClick={() => setShowSettingsModal(true)} className="group relative w-8 h-8 flex items-center justify-center transition-all" title="Connection Status">
                        <div className={`absolute inset-0 rounded-full opacity-20 animate-ping ${isSystemHealthy ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                        <div className={`relative w-2.5 h-2.5 rounded-full shadow-sm ring-2 ring-white dark:ring-slate-900 ${isSystemHealthy ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                    </button>
                    <button onClick={() => setShowAboutModal(true)} className="p-2 rounded-xl text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all" title="About & Release Notes"><Icon name="Info" size={18}/></button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className={`${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} fixed top-16 bottom-0 left-0 z-[60] md:absolute md:inset-y-0 md:relative md:top-0 md:translate-x-0 md:transform-none transition-transform duration-300 ease-soft h-[calc(100%-4rem)] md:h-full`}>
                    <Sidebar 
                        key={sessionKey} 
                        isOpen={isSidebarOpen} 
                        width={sidebarWidth} 
                        setWidth={setSidebarWidth} 
                        standards={allStandards} 
                        standardKey={standardKey} 
                        setStandardKey={handleSetStandardKey} 
                        auditInfo={auditInfo} 
                        setAuditInfo={setAuditInfo} 
                        selectedClauses={selectedClauses} 
                        setSelectedClauses={setSelectedClauses} 
                        onAddNewStandard={() => setShowAddStandardModal(true)} 
                        onUpdateStandard={handleUpdateStandard} 
                        onResetStandard={handleResetStandard} 
                        onReferenceClause={handleOpenReferenceClause} 
                        showIntegrityModal={showIntegrityModal} 
                        setShowIntegrityModal={setShowIntegrityModal}
                        knowledgeFileName={knowledgeFileName}
                        onKnowledgeUpload={handleKnowledgeUpload}
                    />
                </div>
                {isSidebarOpen && <div className="fixed top-16 bottom-0 inset-x-0 bg-black/50 z-50 md:hidden backdrop-blur-sm transition-opacity duration-300 animate-in fade-in" onClick={() => setIsSidebarOpen(false)} />}

                {/* ... (Main Content Layout remains same) ... */}
                <div className={`flex-1 flex flex-col min-w-0 relative w-full transition-all duration-300 ease-soft ${currentTabConfig.bgSoft} border-t-4 ${currentTabConfig.borderClass}`}>

                    <div className="flex-shrink-0 px-4 md:px-6 py-3 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur flex justify-between items-center gap-3">
                        <div className="flex-1 min-w-0">
                            <div ref={tabsContainerRef} className="relative flex justify-between bg-gray-100 dark:bg-slate-950 p-1 rounded-xl w-full dark:shadow-[inset_0_1px_3px_rgba(0,0,0,0.5)]">
                                <div className={`absolute top-1 bottom-1 shadow-sm rounded-lg transition-all duration-500 ease-fluid-spring z-0 ${tabStyle.color}`} style={{ left: tabStyle.left, width: tabStyle.width, opacity: tabStyle.opacity }} />
                                {tabsList.map((tab, idx) => (
                                    <button key={tab.id} ref={el => { tabsRef.current[idx] = el; }} onClick={() => setLayoutMode(tab.id as LayoutMode)} className={`flex-1 relative z-10 flex items-center justify-center gap-2 px-1 md:px-4 py-2 rounded-lg text-xs md:text-sm font-bold transition-colors duration-300 ${layoutMode === tab.id ? 'text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200'}`}>
                                        <Icon name={tab.icon} size={16}/> 
                                        <span className={`${isSidebarOpen ? 'hidden xl:inline' : 'hidden md:inline'}`}>{tab.label}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                        <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                            <button 
                                onClick={() => setShowRecallModal(true)} 
                                className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 border ${lastSavedTime ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800 shadow-sm' : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-gray-200 dark:border-slate-700 hover:bg-gray-50 dark:hover:bg-slate-700 hover:border-gray-300 dark:hover:border-slate-600'}`} 
                                title={lastSavedTime ? `Last Auto-Saved: ${lastSavedTime}. Click to Open Time Machine.` : "Open Session History"}
                            >
                                <div className="relative">
                                    <Icon name="History" size={18}/>
                                    {lastSavedTime && (
                                        <span className="absolute -top-1 -right-1 flex h-2.5 w-2.5">
                                            {isSaving && <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>}
                                            <span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${isSaving ? 'bg-red-500' : 'bg-emerald-500'}`}></span>
                                        </span>
                                    )}
                                </div>
                                <span className="hidden xl:inline text-xs font-bold">Recall</span>
                            </button>

                            <button 
                                onClick={(e) => handleNewSession(e)} 
                                className="h-10 w-10 md:w-auto md:px-4 bg-amber-50 dark:bg-amber-950/30 text-amber-600 dark:text-amber-500 border border-amber-200 dark:border-amber-800/50 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm hover:shadow-amber-500/20 hover:bg-amber-100 dark:hover:bg-amber-900/50 hover:text-amber-700 dark:hover:text-amber-400 duration-300 active:scale-95" 
                                title="Start New Session (Archives current data)"
                            >
                                <Icon name="Session4_FilePlus" size={18}/>
                                <span className="hidden md:inline text-xs font-bold">New</span>
                            </button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-hidden relative p-2 md:p-4">
                        {layoutMode === 'evidence' && (
                            <EvidenceView
                                evidence={evidence}
                                setEvidence={setEvidence}
                                uploadedFiles={uploadedFiles}
                                setUploadedFiles={setUploadedFiles}
                                onOcrProcess={handleOcrUpload}
                                isOcrLoading={isOcrLoading}
                                onAnalyze={handleAnalyze}
                                isReadyForAnalysis={isReadyForAnalysis}
                                isAnalyzeLoading={isAnalyzeLoading}
                                analyzeTooltip={getAnalyzeTooltip()}
                                onExport={startSmartExport}
                                evidenceLanguage={evidenceLanguage}
                                setEvidenceLanguage={setEvidenceLanguage}
                                textareaRef={evidenceTextareaRef}
                            />
                        )}
                        {layoutMode === 'findings' && (
                            <FindingsView
                                analysisResult={analysisResult}
                                setAnalysisResult={setAnalysisResult}
                                selectedFindings={selectedFindings}
                                setSelectedFindings={setSelectedFindings}
                                isAnalyzeLoading={isAnalyzeLoading}
                                loadingMessage={loadingMessage}
                                currentAnalyzingClause={currentAnalyzingClause}
                                viewMode={findingsViewMode}
                                setViewMode={setFindingsViewMode}
                                focusedFindingIndex={focusedFindingIndex}
                                setFocusedFindingIndex={setFocusedFindingIndex}
                                onExport={startSmartExport}
                                notesLanguage={notesLanguage}
                                setNotesLanguage={setNotesLanguage}
                            />
                        )}
                        {layoutMode === 'report' && (
                            <ReportView
                                finalReportText={finalReportText}
                                setFinalReportText={setFinalReportText}
                                isReportLoading={isReportLoading}
                                loadingMessage={loadingMessage}
                                templateFileName={templateFileName}
                                handleTemplateUpload={handleTemplateUpload}
                                handleGenerateReport={handleGenerateReport}
                                isReadyToSynthesize={isReadyToSynthesize}
                                onExport={startSmartExport}
                                exportLanguage={exportLanguage}
                                setExportLanguage={setExportLanguage}
                            />
                        )}
                    </div>
                </div>
            </main>

            <CommandPaletteModal 
                isOpen={isCmdPaletteOpen} 
                onClose={() => setIsCmdPaletteOpen(false)} 
                actions={commandActions} 
                onSelectAction={(action: any) => { action.action(); }} 
            />

            <ReleaseNotesModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />

            <ReferenceClauseModal 
                isOpen={referenceClauseState.isOpen} 
                onClose={() => setReferenceClauseState(prev => ({ ...prev, isOpen: false }))}
                clause={referenceClauseState.clause}
                standardName={allStandards[standardKey]?.name || ""}
                fullText={referenceClauseState.fullText}
                isLoading={referenceClauseState.isLoading}
                onInsert={handleInsertReferenceText}
            />

            <RecallModal
                isOpen={showRecallModal}
                onClose={() => setShowRecallModal(false)}
                onRestore={handleRestoreSnapshot}
            />

            <ExportProgressModal 
                exportState={exportState}
                setExportState={setExportState}
                rescueKey={rescueKey}
                setRescueKey={setRescueKey}
                handleResumeExport={handleResumeExport}
                isRescuing={isRescuing}
            />

            <SettingsModal
                isOpen={showSettingsModal}
                onClose={() => setShowSettingsModal(false)}
                apiKeys={apiKeys}
                newKeyInput={newKeyInput}
                setNewKeyInput={setNewKeyInput}
                isCheckingKey={isCheckingKey}
                handleAddKey={handleAddKey}
                activeKeyId={activeKeyId}
                editingKeyId={editingKeyId}
                editLabelInput={editLabelInput}
                setEditLabelInput={setEditLabelInput}
                handleSaveLabel={handleSaveLabel}
                handleStartEdit={handleStartEdit}
                handleRefreshStatus={handleRefreshStatus}
                handleDeleteKey={handleDeleteKey}
                isAutoCheckEnabled={isAutoCheckEnabled}
                toggleAutoCheck={toggleAutoCheck}
            />

            <AddStandardModal
                isOpen={showAddStandardModal}
                onClose={() => setShowAddStandardModal(false)}
                onAdd={handleAddStandard}
            />
        </div>
    );
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { APP_VERSION, STANDARDS_DATA, INITIAL_EVIDENCE, MODEL_HIERARCHY, MY_FIXED_KEYS, BUILD_TIMESTAMP, DEFAULT_AUDIT_INFO } from './constants';
import { StandardsData, AuditInfo, AnalysisResult, Standard, ApiKeyProfile, Clause, FindingsViewMode, SessionSnapshot } from './types';
import { Icon, FontSizeController, Toast, CommandPaletteModal } from './components/UI';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import ReferenceClauseModal from './components/ReferenceClauseModal';
import RecallModal from './components/RecallModal';
import { generateOcrContent, generateAnalysis, generateTextReport, validateApiKey, fetchFullClauseText } from './services/geminiService';
import { cleanAndParseJSON, fileToBase64, cleanFileName, copyToClipboard, extractTextFromPdf } from './utils';

// New Component Imports
import { EvidenceView } from './components/views/EvidenceView';
import { FindingsView } from './components/views/FindingsView';
import { ReportView } from './components/views/ReportView';
import { SettingsModal } from './components/modals/SettingsModal';
import { ExportProgressModal, ExportState } from './components/modals/ExportProgressModal';
import { AddStandardModal } from './components/modals/AddStandardModal';

declare var mammoth: any;

type LayoutMode = 'evidence' | 'findings' | 'report';
type ExportLanguage = 'en' | 'vi';

export interface UploadedFile {
    id: string;
    file: File;
    status: 'pending' | 'processing' | 'success' | 'error';
    error?: string;
    result?: string;
}

export default function App() {
    // -- STATE --
    const [sessionKey, setSessionKey] = useState(Date.now());

    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isDarkMode, setIsDarkMode] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(420); 
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [showAboutModal, setShowAboutModal] = useState(false);
    const [showSettingsModal, setShowSettingsModal] = useState(false);
    const [showIntegrityModal, setShowIntegrityModal] = useState(false);
    const [showRecallModal, setShowRecallModal] = useState(false); 
    const [showAddStandardModal, setShowAddStandardModal] = useState(false);

    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);
    const [findingsViewMode, setFindingsViewMode] = useState<FindingsViewMode>('list');
    const [focusedFindingIndex, setFocusedFindingIndex] = useState<number>(0); 

    const [apiKeys, setApiKeys] = useState<ApiKeyProfile[]>([]);
    const [activeKeyId, setActiveKeyId] = useState<string>("");
    const [newKeyInput, setNewKeyInput] = useState("");
    const [newKeyLabel, setNewKeyLabel] = useState("");
    const [isCheckingKey, setIsCheckingKey] = useState(false);

    const [isAutoCheckEnabled, setIsAutoCheckEnabled] = useState(false);

    const [editingKeyId, setEditingKeyId] = useState<string | null>(null);
    const [editLabelInput, setEditLabelInput] = useState("");

    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const [lastSavedTime, setLastSavedTime] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false); 

    const isRestoring = useRef(false);
    const isManuallyCleared = useRef(false);

    // KNOWLEDGE BASE (Source Data)
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    const [referenceClauseState, setReferenceClauseState] = useState<{
        isOpen: boolean;
        clause: Clause | null;
        fullText: { en: string; vi: string };
        isLoading: boolean;
    }>({
        isOpen: false,
        clause: null,
        fullText: { en: "", vi: "" },
        isLoading: false,
    });

    const [exportLanguage, setExportLanguage] = useState<ExportLanguage>('en');
    const [notesLanguage, setNotesLanguage] = useState<ExportLanguage>('vi'); 
    const [evidenceLanguage, setEvidenceLanguage] = useState<ExportLanguage>('en'); 

    const [reportTemplate, setReportTemplate] = useState<string>("");
    const [templateFileName, setTemplateFileName] = useState<string>("");

    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);

    const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);

    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);
    const [layoutMode, setLayoutMode] = useState('evidence' as LayoutMode);

    const [isOcrLoading, setIsOcrLoading] = useState(false);
    const [isAnalyzeLoading, setIsAnalyzeLoading] = useState(false);
    const [currentAnalyzingClause, setCurrentAnalyzingClause] = useState<string>(""); 
    const [loadingMessage, setLoadingMessage] = useState<string>(""); 
    const [isReportLoading, setIsReportLoading] = useState(false);

    const [exportState, setExportState] = useState<ExportState>({
        isOpen: false,
        isPaused: false,
        isFinished: false,
        totalChunks: 0,
        processedChunksCount: 0,
        chunks: [],
        results: [],
        error: null,
        currentType: 'report',
        targetLang: 'en'
    });

    const [aiError, setAiError] = useState<string | null>(null);
    const [isErrorClosing, setIsErrorClosing] = useState(false);
    const [rescueKey, setRescueKey] = useState("");
    const [isRescuing, setIsRescuing] = useState(false);

    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);
    const tabsContainerRef = useRef<HTMLDivElement>(null); 
    const [tabStyle, setTabStyle] = useState({ left: 0, width: 0, opacity: 0, color: '' });

    const tabsList = [
        { id: 'evidence', label: '1. Evidence', icon: 'ScanText', colorClass: 'bg-blue-500', textClass: 'text-blue-600', borderClass: 'border-blue-500', bgSoft: 'bg-blue-50 dark:bg-blue-950/30' }, 
        { id: 'findings', label: '2. Findings', icon: 'Wand2', colorClass: 'bg-purple-500', textClass: 'text-purple-600', borderClass: 'border-purple-500', bgSoft: 'bg-purple-50 dark:bg-purple-950/30' }, 
        { id: 'report', label: '3. Report', icon: 'FileText', colorClass: 'bg-emerald-500', textClass: 'text-emerald-600', borderClass: 'border-emerald-500', bgSoft: 'bg-emerald-50 dark:bg-emerald-950/30' }
    ];

    const currentTabConfig = tabsList.find(t => t.id === layoutMode) || tabsList[0];
    const evidenceTextareaRef = useRef<HTMLTextAreaElement>(null);

    const allStandards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const hasEvidence = evidence.trim().length > 0 || uploadedFiles.length > 0;

    const isReadyForAnalysis = !isAnalyzeLoading && selectedClauses.length > 0 && hasEvidence;
    const isReadyToSynthesize = !isReportLoading && analysisResult && Object.values(selectedFindings).some(v => v);

    const poolStats = useMemo(() => {
        const total = apiKeys.length;
        const valid = apiKeys.filter(k => k.status === 'valid').length;
        return { total, valid };
    }, [apiKeys]);

    const activeKeyProfile = useMemo(() => apiKeys.find(k => k.id === activeKeyId), [apiKeys, activeKeyId]);
    const isSystemHealthy = activeKeyProfile?.status === 'valid';

    // ... (Keep existing loadKeyData, Background Checker, etc. same as before) ...
    const loadKeyData = (): ApiKeyProfile[] => {
        try {
            const stored = localStorage.getItem("iso_api_keys");
            const loadedKeys: ApiKeyProfile[] = stored ? JSON.parse(stored) : [];
            const existingKeySet = new Set(loadedKeys.map(k => k.key));
            let hasChanges = false;
            MY_FIXED_KEYS.forEach((fixedKey, index) => {
                if (fixedKey && !existingKeySet.has(fixedKey)) {
                    loadedKeys.push({ id: `fixed_key_${index}_${Math.random().toString(36).substr(2, 5)}`, label: `Environment Key ${index + 1}`, key: fixedKey, status: 'unknown', latency: 0, lastChecked: new Date().toISOString() });
                    hasChanges = true;
                }
            });
            if (hasChanges) localStorage.setItem("iso_api_keys", JSON.stringify(loadedKeys));
            const savedActiveId = localStorage.getItem("iso_active_key_id");
            if (savedActiveId && loadedKeys.some(k => k.id === savedActiveId)) setActiveKeyId(savedActiveId);
            else if (loadedKeys.length > 0 && !activeKeyId) setActiveKeyId(loadedKeys[0].id);
            return loadedKeys;
        } catch (e) { console.error("Failed to load keys", e); return []; }
    };

    // --- PERSISTENT KNOWLEDGE BASE STORAGE ---
    const getStorageKey = (stdKey: string) => `iso_kb_content_${stdKey}`;
    const getStorageNameKey = (stdKey: string) => `iso_kb_name_${stdKey}`;

    const loadKnowledgeForStandard = (key: string) => {
        try {
            const savedContent = localStorage.getItem(getStorageKey(key));
            const savedName = localStorage.getItem(getStorageNameKey(key));
            if (savedContent && savedName) {
                setKnowledgeBase(savedContent);
                setKnowledgeFileName(savedName);
                setToastMsg(`Restored source document for ${allStandards[key]?.name || key}`);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) {
            console.error("Failed to load KB", e);
        }
    };

    const saveKnowledgeToStorage = (key: string, content: string, fileName: string) => {
        try {
            localStorage.setItem(getStorageKey(key), content);
            localStorage.setItem(getStorageNameKey(key), fileName);
        } catch (e) {
            console.error("Storage Quota Exceeded for KB", e);
            setToastMsg("Warning: Document too large to save for future sessions (Quota Exceeded). It will work for this session only.");
        }
    };

    // --- CRITICAL: Reset/Restore Knowledge Base when Standard changes ---
    const handleSetStandardKey = (key: string) => {
        if (key !== standardKey) {
            setStandardKey(key);
            // Attempt to load existing KB for this new key
            loadKnowledgeForStandard(key);
        }
    };

    useEffect(() => {
        if (!isAutoCheckEnabled) return;
        const intervalId = setInterval(() => {
            if (!isAnalyzeLoading && !isOcrLoading && !isReportLoading && !isCheckingKey && apiKeys.length > 0) performBackgroundHealthCheck();
        }, 45000); 
        return () => clearInterval(intervalId);
    }, [isAutoCheckEnabled, isAnalyzeLoading, isOcrLoading, isReportLoading, isCheckingKey, apiKeys]);

    const performBackgroundHealthCheck = async () => {
        const sortedKeys = [...apiKeys].sort((a, b) => new Date(a.lastChecked || 0).getTime() - new Date(b.lastChecked || 0).getTime());
        const candidate = sortedKeys[0]; if (!candidate) return;
        setApiKeys(prev => prev.map(k => k.id === candidate.id ? { ...k, status: 'checking' } : k));
        const cap = await determineKeyCapabilities(candidate.key);
        const today = new Date().toISOString().split('T')[0];
        setApiKeys(prev => prev.map(k => k.id === candidate.id ? { ...k, status: cap.status, activeModel: cap.activeModel || k.activeModel, latency: cap.latency, lastChecked: new Date().toISOString(), lastResetDate: today } : k));
    };

    const dismissError = () => { setIsErrorClosing(true); setTimeout(() => { setAiError(null); setIsErrorClosing(false); }, 300); };

    const handleGenericError = (e: any) => {
        const msg = e.message || "Unknown error";
        if (msg.includes("ALL_KEYS_EXHAUSTED")) { setAiError("All API Keys have been exhausted or Quota exceeded."); setShowSettingsModal(true); }
        else if (msg.includes("API Key is missing")) { setToastMsg("API Key is required. Please check settings."); setShowSettingsModal(true); }
        else setAiError(msg);
    };

    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart; const end = textarea.selectionEnd; const currentText = textarea.value;
            const textWithBreaks = `\n${textToInsert.trim()}\n`;
            const newValue = currentText.substring(0, start) + textWithBreaks + currentText.substring(end);
            setEvidence(newValue);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
            setTimeout(() => { if (evidenceTextareaRef.current) { evidenceTextareaRef.current.focus(); evidenceTextareaRef.current.setSelectionRange(start + textWithBreaks.length, start + textWithBreaks.length); } }, 100);
        } else {
            setEvidence(prev => prev + "\n" + textToInsert.trim());
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    const determineKeyCapabilities = async (key: string): Promise<{ status: 'valid' | 'invalid' | 'quota_exceeded' | 'referrer_error' | 'unknown', activeModel?: string, latency: number }> => {
        const result = await validateApiKey(key);
        let status: 'valid' | 'invalid' | 'quota_exceeded' | 'referrer_error' | 'unknown' = 'unknown';
        if (result.isValid) status = 'valid';
        else if (result.errorType === 'network_error') status = 'unknown'; 
        else if (result.errorType) status = result.errorType as any;
        return { status, activeModel: result.activeModel, latency: result.latency };
    };

    const checkAllKeys = async (initialKeys: ApiKeyProfile[]) => {
        setIsCheckingKey(true); 
        setApiKeys(prev => prev.map(k => ({ ...k, status: 'checking' })));
        const today = new Date().toISOString().split('T')[0]; 
        const updatedKeys = [...initialKeys];
        for (let i = 0; i < updatedKeys.length; i++) {
            const profile = updatedKeys[i]; 
            const cap = await determineKeyCapabilities(profile.key);
            updatedKeys[i] = { 
                ...profile, 
                status: cap.status, 
                activeModel: cap.activeModel, 
                latency: cap.latency, 
                lastChecked: new Date().toISOString(), 
                lastResetDate: today 
            };
            setApiKeys(prev => {
                const newArr = [...prev];
                const idx = newArr.findIndex(k => k.id === profile.id);
                if (idx !== -1) newArr[idx] = updatedKeys[i];
                return newArr;
            });
            await new Promise(r => setTimeout(r, 100));
        }
        setApiKeys(currentKeys => {
            const currentActiveProfile = currentKeys.find(k => k.id === activeKeyId);
            if (!currentActiveProfile || (currentActiveProfile.status !== 'valid' && currentActiveProfile.status !== 'unknown')) {
                const bestKey = currentKeys.filter(k => k.status === 'valid').sort((a, b) => a.latency - b.latency)[0];
                if (bestKey) { 
                    setActiveKeyId(bestKey.id); 
                    localStorage.setItem("iso_active_key_id", bestKey.id);
                    setTimeout(() => setToastMsg(`Auto-switched to healthy key: ${bestKey.label}`), 0); 
                } 
            }
            localStorage.setItem("iso_api_keys", JSON.stringify(currentKeys));
            return currentKeys;
        });
        setIsCheckingKey(false);
    };

    const handleRefreshStatus = async (id: string) => {
        const keyProfile = apiKeys.find(k => k.id === id); 
        if (!keyProfile) return;
        setApiKeys(prev => prev.map(k => k.id === id ? { ...k, status: 'checking' } : k));
        const cap = await determineKeyCapabilities(keyProfile.key);
        setApiKeys(prev => {
            const next = prev.map(k => k.id === id ? { 
                ...k, 
                status: cap.status, 
                activeModel: cap.activeModel || k.activeModel, 
                latency: cap.latency, 
                lastChecked: new Date().toISOString() 
            } : k);
            localStorage.setItem("iso_api_keys", JSON.stringify(next));
            return next;
        });
    };

    const handleAddKey = async () => {
        if (!newKeyInput.trim()) return;
        if (apiKeys.some(k => k.key === newKeyInput.trim())) { setToastMsg("This API Key is already in your pool!"); setNewKeyInput(""); return; }
        setIsCheckingKey(true); 
        const tempId = Date.now().toString(); 
        const cap = await determineKeyCapabilities(newKeyInput);
        const newProfile: ApiKeyProfile = { 
            id: tempId, 
            label: newKeyLabel || `Key ${apiKeys.length + 1}`, 
            key: newKeyInput, 
            status: cap.status, 
            activeModel: cap.activeModel, 
            latency: cap.latency, 
            lastChecked: new Date().toISOString(), 
            lastResetDate: new Date().toISOString().split('T')[0] 
        };
        const nextKeys = [...apiKeys, newProfile];
        setApiKeys(nextKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(nextKeys));
        if (apiKeys.length === 0 || (activeKeyProfile?.status !== 'valid' && cap.status === 'valid')) {
            setActiveKeyId(tempId);
            localStorage.setItem("iso_active_key_id", tempId);
        }
        setNewKeyInput(""); setNewKeyLabel(""); setIsCheckingKey(false);
        if(cap.status === 'valid') setToastMsg("Key added successfully!");
        else if (cap.status === 'referrer_error') setAiError("Key restricted! Check 'HTTP Referrers' in Google Cloud Console.");
        else setAiError("The key you added appears invalid or network is blocking it.");
    };

    const handleDeleteKey = (id: string) => {
        const nextKeys = apiKeys.filter(k => k.id !== id);
        let newActiveId = activeKeyId;
        if (activeKeyId === id) {
            const nextBest = nextKeys.find(k => k.status === 'valid') || nextKeys[0];
            newActiveId = nextBest ? nextBest.id : "";
        }
        setApiKeys(nextKeys);
        if (newActiveId !== activeKeyId) setActiveKeyId(newActiveId);
        localStorage.setItem("iso_api_keys", JSON.stringify(nextKeys));
        if (newActiveId) localStorage.setItem("iso_active_key_id", newActiveId);
        else localStorage.removeItem("iso_active_key_id");
        setToastMsg("Key removed from pool.");
    };

    const executeWithSmartFailover = async <T,>(operation: (apiKey: string, model: string) => Promise<T>): Promise<T> => {
        const candidates = apiKeys.filter(k => k.status !== 'invalid').sort((a, b) => {
            if (a.status === 'valid' && b.status !== 'valid') return -1;
            if (a.status !== 'valid' && b.status === 'valid') return 1;
            if (a.id === activeKeyId) return -1;
            if (b.id === activeKeyId) return 1;
            return a.latency - b.latency;
        });
        if (candidates.length === 0) throw new Error("API Key is missing or all keys are invalid.");
        let lastError: any;
        for (const profile of candidates) {
            const modelToUse = profile.activeModel || MODEL_HIERARCHY[0];
            try {
                if (profile.id !== activeKeyId) setActiveKeyId(profile.id);
                const result = await operation(profile.key, modelToUse);
                return result;
            } catch (error: any) {
                console.warn(`Key ${profile.label} failed on ${modelToUse}:`, error); lastError = error;
                const msg = (error.message || "").toLowerCase();
                if (msg.includes("429") || msg.includes("quota") || msg.includes("resource exhausted")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'quota_exceeded' } : k));
                else if (msg.includes("403") || msg.includes("key not valid") || msg.includes("permission denied")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'invalid' } : k));
            }
        }
        throw new Error(lastError?.message || "ALL_KEYS_EXHAUSTED");
    };

    const loadSessionData = () => {
        try {
            const session = localStorage.getItem("iso_session_data");
            const customStds = localStorage.getItem("iso_custom_standards");
            if (customStds) setCustomStandards(JSON.parse(customStds));
            if (session) {
                const data = JSON.parse(session);
                if (data.standardKey) {
                    setStandardKey(data.standardKey);
                    // Also attempt to load knowledge base for this standard
                    loadKnowledgeForStandard(data.standardKey);
                }
                if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
                if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
                if (data.evidence) setEvidence(data.evidence);
                if (data.analysisResult) setAnalysisResult(data.analysisResult);
                if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
                if (data.finalReportText) setFinalReportText(data.finalReportText);
                setLastSavedTime(new Date().toLocaleTimeString());
                setToastMsg("Previous session restored.");
            }
        } catch (e) { console.error("Load failed", e); }
    };

    const handleUpdateStandard = (std: Standard) => { setCustomStandards(prev => ({ ...prev, [standardKey]: std })); setToastMsg("Standard updated successfully."); };
    const handleResetStandard = (key: string) => { setCustomStandards(prev => { const next = { ...prev }; delete next[key]; return next; }); setToastMsg("Standard reset to default."); };

    // --- INTEGRATED SOURCE FILE PROCESSING ---
    const processSourceFile = async (file: File): Promise<string> => {
        let text = "";
        try {
            if (file.name.endsWith('.pdf')) {
                text = await extractTextFromPdf(file);
            } else if (file.name.endsWith('.docx')) {
                if (typeof mammoth === 'undefined') throw new Error("Mammoth library missing");
                const arrayBuffer = await file.arrayBuffer();
                const result = await mammoth.extractRawText({ arrayBuffer });
                text = result.value;
            } else {
                text = await file.text();
            }
            if (!text || text.length < 50) throw new Error("File content is too short or empty.");
            return text;
        } catch (err: any) {
            console.error("File processing error:", err);
            throw new Error(`Failed to parse ${file.name}: ${err.message}`);
        }
    };

    // --- KNOWLEDGE BASE UPLOAD (EXISTING STANDARD) ---
    const handleKnowledgeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; 
        if (!file) return; 

        setKnowledgeFileName(file.name);
        setToastMsg("Parsing Standard Document...");

        try {
            const text = await processSourceFile(file);
            setKnowledgeBase(text);
            setToastMsg(`Standard Loaded (${(text.length / 1024).toFixed(0)}KB). Saving for future use...`);

            // Save to persistent storage
            if (standardKey) {
                saveKnowledgeToStorage(standardKey, text, file.name);
            }
        } catch (err: any) {
            setToastMsg(err.message);
            setKnowledgeFileName(null);
            setKnowledgeBase(null);
        }
    };

    // --- ADD NEW STANDARD (INTEGRATED FLOW) ---
    const handleAddStandard = async (name: string, file: File | null) => {
        setShowAddStandardModal(false);
        const newKey = `CUSTOM_${Date.now()}`;

        // 1. Create Base Structure
        const newStandard: Standard = {
            name: name,
            description: `Custom Standard created on ${new Date().toLocaleDateString()}`,
            groups: [{
                id: `GRP_${Date.now()}`,
                title: "General Requirements",
                icon: "Book",
                clauses: [
                    { id: `CL_${Date.now()}_1`, code: "1", title: "General", description: "Requirement details pending AI extraction." }
                ]
            }]
        };

        // 2. Process File if attached
        if (file) {
            setToastMsg("Processing source document...");
            try {
                const text = await processSourceFile(file);
                setKnowledgeBase(text);
                setKnowledgeFileName(file.name);
                saveKnowledgeToStorage(newKey, text, file.name);
            } catch (err: any) {
                setToastMsg(`Standard created, but file failed: ${err.message}`);
            }
        } else {
            setKnowledgeBase(null);
            setKnowledgeFileName(null);
        }

        // 3. Update State
        setCustomStandards(prev => ({ ...prev, [newKey]: newStandard }));
        setStandardKey(newKey);
        setToastMsg(`Created new standard: ${name}`);
    };

    // ... (Auto Save, BeforeUnload, New Session, Restore, OCR, Export, Analyze, Report - kept same) ...
    // --- ROBUST AUTO-SAVE LOGIC ---
    useEffect(() => {
        if (isRestoring.current) return;
        const isEmptyState = !evidence && (!selectedClauses || selectedClauses.length === 0);
        if (isEmptyState && !isManuallyCleared.current) {
            if (localStorage.getItem("iso_session_data")) {
                return; 
            }
        }
        setIsSaving(true);
        const handler = setTimeout(() => {
            if (isRestoring.current) {
                setIsSaving(false);
                return;
            }
            const sessionData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
            localStorage.setItem("iso_session_data", JSON.stringify(sessionData));
            localStorage.setItem("iso_custom_standards", JSON.stringify(customStandards));
            localStorage.setItem("iso_api_keys", JSON.stringify(apiKeys));
            if (isManuallyCleared.current) isManuallyCleared.current = false;
            const now = new Date();
            setLastSavedTime(now.toLocaleTimeString());
            setIsSaving(false);
        }, 800); 
        return () => clearTimeout(handler);
    }, [standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText, customStandards, apiKeys]);

    useEffect(() => {
        const handleBeforeUnload = (e: BeforeUnloadEvent) => {
            if (!isRestoring.current) {
                const sessionData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
                localStorage.setItem("iso_session_data", JSON.stringify(sessionData));
            }
        };
        window.addEventListener('beforeunload', handleBeforeUnload);
        return () => window.removeEventListener('beforeunload', handleBeforeUnload);
    }, [standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText]);

    const handleNewSession = (e?: any) => { 
        if(e) e.stopPropagation(); 
        if(!confirm("Start New Session? Current data will be moved to 'Backup Vault'.")) return; 
        try {
            const currentData = { standardKey, auditInfo, selectedClauses, evidence, analysisResult, selectedFindings, finalReportText };
            const hasData = evidence.trim().length > 0 || selectedClauses.length > 0;
            if (hasData) {
                const snapshot: SessionSnapshot = {
                    id: `backup_${Date.now()}`,
                    timestamp: Date.now(),
                    label: "Backup (Pre-Reset)",
                    triggerType: "MANUAL_BACKUP",
                    data: currentData
                };
                const historyRaw = localStorage.getItem("iso_session_history");
                const history = historyRaw ? JSON.parse(historyRaw) : [];
                const newHistory = [snapshot, ...history].slice(0, 5);
                localStorage.setItem("iso_session_history", JSON.stringify(newHistory));
            }
            isManuallyCleared.current = true;
            localStorage.removeItem("iso_session_data");
            setStandardKey("");
            setAuditInfo(DEFAULT_AUDIT_INFO); 
            setEvidence(""); 
            setSelectedClauses([]); 
            setUploadedFiles([]); 
            setAnalysisResult(null); 
            setSelectedFindings({}); 
            setFinalReportText(null); 
            setLastSavedTime(null); 
            setSessionKey(Date.now());
            setKnowledgeBase(null); 
            setKnowledgeFileName(null);
            setLayoutMode('evidence'); 
            setToastMsg("New Session Started. (Previous session archived in Recall)");
        } catch (error) {
            console.error("New Session Error", error);
            setToastMsg("Error creating backup. Session reset anyway.");
        }
    };

    const handleRestoreSnapshot = (snapshot: SessionSnapshot) => {
        try {
            isRestoring.current = true;
            setShowRecallModal(false);
            const data = snapshot.data;
            localStorage.setItem("iso_session_data", JSON.stringify(data));
            if (data.standardKey) {
                setStandardKey(data.standardKey);
                loadKnowledgeForStandard(data.standardKey);
            }
            setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...(data.auditInfo || {}) });
            if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
            if (data.evidence !== undefined) setEvidence(data.evidence);
            setUploadedFiles([]); 
            if (data.analysisResult) setAnalysisResult(data.analysisResult);
            if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
            if (data.finalReportText) setFinalReportText(data.finalReportText);
            setSessionKey(Date.now());
            const now = new Date();
            setLastSavedTime(now.toLocaleTimeString());
            setToastMsg(`Restored session from: ${new Date(snapshot.timestamp).toLocaleTimeString()}`);
            setTimeout(() => {
                isRestoring.current = false;
                isManuallyCleared.current = false; 
            }, 1200);
        } catch (e) {
            console.error("Restore failed", e);
            setToastMsg("Failed to restore session snapshot.");
            isRestoring.current = false;
        }
    };

    const handleOcrUpload = async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;
        setIsOcrLoading(true); setLoadingMessage("Processing documents with Vision AI...");
        let processedCount = 0;
        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));
                let text = "";
                if (fileEntry.file.type === 'text/plain') text = await fileEntry.file.text();
                else {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await executeWithSmartFailover(async (key, model) => generateOcrContent("Extract all text.", base64, fileEntry.file.type, key, model));
                }
                if (text) {
                    const separator = `\n\n--- FILE: ${fileEntry.file.name} ---\n`;
                    insertTextAtCursor(separator + text);
                    setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: text } : f));
                    processedCount++;
                } else throw new Error("No text extracted");
            } catch (error: any) {
                console.error("OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsOcrLoading(false); setLoadingMessage(""); setToastMsg(`Processed ${processedCount} files.`);
    };

    const handleTemplateUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file) return; setTemplateFileName(file.name);
        try {
            if (file.name.endsWith('.docx')) {
                if (typeof mammoth === 'undefined') { alert("Mammoth library not loaded for .docx support"); return; }
                const arrayBuffer = await file.arrayBuffer(); const result = await mammoth.extractRawText({ arrayBuffer }); setReportTemplate(result.value);
            } else { const text = await file.text(); setReportTemplate(text); }
            setToastMsg("Template loaded successfully.");
        } catch (err) { setToastMsg("Failed to load template."); console.error(err); }
    };

    const startSmartExport = (content: string, type: 'notes' | 'report' | 'evidence', lang: ExportLanguage) => {
        if (!content) return;
        const CHUNK_SIZE = 4000; const chunks = []; for (let i = 0; i < content.length; i += CHUNK_SIZE) chunks.push(content.substring(i, i + CHUNK_SIZE));
        setExportState({ isOpen: true, isPaused: false, isFinished: false, totalChunks: chunks.length, processedChunksCount: 0, chunks, results: new Array(chunks.length).fill(""), error: null, currentType: type, targetLang: lang });
    };

    const toggleAutoCheck = (enabled: boolean) => { setIsAutoCheckEnabled(enabled); localStorage.setItem('iso_auto_check', String(enabled)); setToastMsg(enabled ? "Auto-health check enabled." : "Auto-health check disabled."); };
    const handleStartEdit = (keyProfile: ApiKeyProfile) => { setEditingKeyId(keyProfile.id); setEditLabelInput(keyProfile.label); };
    const handleSaveLabel = () => { if (editingKeyId) { setApiKeys(prev => prev.map(k => k.id === editingKeyId ? { ...k, label: editLabelInput } : k)); setEditingKeyId(null); } };


    const handleOpenReferenceClause = async (clause: Clause) => {
        setReferenceClauseState({ isOpen: true, clause, isLoading: true, fullText: { en: "", vi: "" } });
        try {
            const text = await executeWithSmartFailover(async (key, model) => fetchFullClauseText(clause, allStandards[standardKey].name, knowledgeBase, key, model));
            setReferenceClauseState(prev => ({ ...prev, isLoading: false, fullText: text }));
        } catch (e: any) {
            setReferenceClauseState({ isOpen: false, clause: null, isLoading: false, fullText: { en: "", vi: "" } });
            setAiError("API Failed during lookup."); setShowSettingsModal(true); 
        }
    };

    const handleInsertReferenceText = (text: string) => {
        if (!referenceClauseState.clause) return;
        const quoteText = `\n--- REFERENCE: [${referenceClauseState.clause.code}] ${referenceClauseState.clause.title} ---\n${text}\n--- END REFERENCE ---\n`.trim();
        insertTextAtCursor(quoteText);
        setReferenceClauseState({ isOpen: false, clause: null, isLoading: false, fullText: { en: "", vi: "" } });
    };

    // --- MISSING FUNCTIONS IMPLEMENTATION ---
    const handleAnalyze = async () => {
        if (!standardKey) { setToastMsg("Select a Standard first."); return; }
        if (selectedClauses.length === 0) { setToastMsg("Select at least one Clause to analyze."); return; }
        if (!hasEvidence) { setToastMsg("No evidence provided. Please add text or files."); return; }

        setIsAnalyzeLoading(true);
        setLayoutMode('findings');
        // Reset or prepare results
        // For fresh analysis on new evidence, typically we might want to clear old results.
        // Or we could append. Let's reset for this implementation to be clean.
        setAnalysisResult(null);

        try {
             const allClausesFlat = allStandards[standardKey].groups.flatMap(g => g.clauses);
             const findClause = (id: string, list: Clause[]): Clause | undefined => {
                for (let c of list) { if (c.id === id) return c; if (c.subClauses) { const f = findClause(id, c.subClauses); if (f) return f; } }
             };

             const targets = selectedClauses.map(id => findClause(id, allClausesFlat)).filter(c => !!c) as Clause[];

             // Construct context from evidence and processed files
             let fullEvidenceContext = evidence;
             uploadedFiles.filter(f => f.status === 'success' && f.result).forEach(f => {
                 fullEvidenceContext += `\n\n--- Document: ${f.file.name} ---\n${f.result}`;
             });

             const newResults: AnalysisResult[] = [];
             const newSelections: Record<string, boolean> = {};

             for (let i = 0; i < targets.length; i++) {
                 const clause = targets[i];
                 setCurrentAnalyzingClause(clause.code);
                 setLoadingMessage(`Analyzing Clause ${clause.code}...`);

                 const prompt = `
                 Analyze the provided EVIDENCE against ISO Standard "${allStandards[standardKey].name}", Clause "${clause.code}: ${clause.title}".
                 Clause Description: ${clause.description}

                 EVIDENCE:
                 """
                 ${fullEvidenceContext.substring(0, 50000)} 
                 """

                 DETERMINE:
                 1. Status (COMPLIANT, NC_MINOR, NC_MAJOR, OFI, or N_A).
                 2. Reason (Why?).
                 3. Evidence Quote (Verbatim support).
                 4. Suggestion (If NC or OFI).

                 Output JSON Array with 1 object: [{ "clauseId": "${clause.code}", "status": "...", "reason": "...", "evidence": "...", "suggestion": "..." }]
                 `;

                 // Using executeWithSmartFailover to handle keys
                 const jsonStr = await executeWithSmartFailover((key, model) => generateAnalysis(prompt, "You are a lead ISO Auditor.", key, model));
                 const parsed = cleanAndParseJSON(jsonStr);

                 if (Array.isArray(parsed) && parsed.length > 0) {
                     const item = parsed[0];
                     item.clauseId = clause.code; 
                     newResults.push(item);
                     newSelections[clause.code] = true;
                 } else {
                     newResults.push({
                         clauseId: clause.code,
                         status: 'N_A',
                         reason: 'AI could not determine status.',
                         evidence: '',
                         suggestion: '',
                         conclusion_report: ''
                     });
                     newSelections[clause.code] = true;
                 }
             }

             setAnalysisResult(newResults);
             setSelectedFindings(newSelections);
             setToastMsg(`Analysis Complete. Generated ${newResults.length} findings.`);

        } catch (e: any) {
            handleGenericError(e);
        } finally {
            setIsAnalyzeLoading(false);
            setLoadingMessage("");
            setCurrentAnalyzingClause("");
        }
    };

    const handleGenerateReport = async () => {
        if (!analysisResult || analysisResult.length === 0) {
            setToastMsg("No findings available to report.");
            return;
        }

        const activeFindings = analysisResult.filter(r => selectedFindings[r.clauseId]);
        if (activeFindings.length === 0) {
            setToastMsg("Please select at least one finding to include in the report.");
            return;
        }

        setIsReportLoading(true);
        setLoadingMessage("Synthesizing Final Audit Report...");

        try {
            const prompt = `
            Generate a comprehensive ISO Audit Report.

            Entity: ${auditInfo.company}
            Type: ${auditInfo.type}
            Auditor: ${auditInfo.auditor}
            Standard: ${allStandards[standardKey]?.name}

            FINDINGS TO INCLUDE:
            ${JSON.stringify(activeFindings)}

            TEMPLATE / INSTRUCTIONS:
            ${reportTemplate || "Use standard professional ISO audit report format including Executive Summary, Audit Scope, Findings Detail, and Conclusion."}

            Language: ${exportLanguage === 'vi' ? 'Vietnamese' : 'English'}.
            Tone: Professional, Objective.
            `;

            const report = await executeWithSmartFailover((key, model) => generateTextReport(prompt, "You are an expert ISO Certification Body Auditor.", key, model));
            setFinalReportText(report);
            setLayoutMode('report');
            setToastMsg("Report Generated Successfully.");
        } catch (e: any) {
            handleGenericError(e);
        } finally {
            setIsReportLoading(false);
            setLoadingMessage("");
        }
    };

    // Export Processing Effect
    useEffect(() => {
        if (!exportState.isOpen || exportState.isPaused || exportState.isFinished) return;

        const processChunk = async () => {
            const idx = exportState.processedChunksCount;
            if (idx >= exportState.totalChunks) {
                setExportState(prev => ({ ...prev, isFinished: true }));
                try {
                    const finalContent = exportState.results.join("");
                    const blob = new Blob([finalContent], { type: 'text/plain' });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = `ISO_Audit_Export_${exportState.currentType}_${new Date().toISOString()}.txt`;
                    document.body.appendChild(a);
                    a.click();
                    document.body.removeChild(a);
                    URL.revokeObjectURL(url);
                } catch(e) { console.error("Download failed", e); }
                return;
            }

            const chunk = exportState.chunks[idx];
            try {
                let result = chunk;
                if (exportState.targetLang !== 'en' && exportState.targetLang !== 'vi') { 
                    // Should not happen based on types
                } else if (exportState.targetLang !== 'en') {
                     const prompt = `Translate this text to ${exportState.targetLang === 'vi' ? 'Vietnamese' : 'English'} maintaining formatting:\n\n${chunk}`;
                     result = await executeWithSmartFailover((key, model) => generateTextReport(prompt, "Translator", key, model));
                }

                setExportState(prev => {
                    const newResults = [...prev.results];
                    newResults[idx] = result;
                    return { ...prev, processedChunksCount: idx + 1, results: newResults };
                });
            } catch (e: any) {
                console.error("Export Error", e);
                setExportState(prev => ({ ...prev, isPaused: true, error: e.message }));
            }
        };
        processChunk();
    }, [exportState, executeWithSmartFailover]);

    const handleResumeExport = async () => {
        setIsRescuing(true);
        try {
            if (rescueKey.trim()) {
                const cap = await determineKeyCapabilities(rescueKey);
                if (cap.status === 'valid') {
                     const newProfile: ApiKeyProfile = { 
                        id: `rescue_${Date.now()}`, 
                        label: `Rescue Key`, 
                        key: rescueKey, 
                        status: 'valid', 
                        activeModel: cap.activeModel,
                        latency: cap.latency, 
                        lastChecked: new Date().toISOString() 
                    };
                    setApiKeys(prev => [...prev, newProfile]);
                    setActiveKeyId(newProfile.id);
                    setToastMsg("Rescue Key Added. Resuming...");
                    setExportState(prev => ({ ...prev, isPaused: false, error: null }));
                    setRescueKey("");
                } else {
                    setToastMsg("Rescue Key Invalid/Exhausted.");
                }
            } else {
                setExportState(prev => ({ ...prev, isPaused: false, error: null }));
            }
        } catch (e) {
            setToastMsg("Failed to resume.");
        } finally {
            setIsRescuing(false);
        }
    };
    // ------------------------------------

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => { if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); setIsCmdPaletteOpen(prev => !prev); } };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    const commandActions = useMemo(() => {
        const baseActions: any[] = [
            { label: "Analyze Compliance", desc: `Start AI analysis`, icon: "Wand2", shortcut: "AI", action: handleAnalyze },
            { label: "Validate API Key Pool", desc: "Check connection health", icon: "RefreshCw", action: () => { checkAllKeys(apiKeys); setToastMsg("Validating Neural Pool..."); } },
            { label: "Settings", desc: "Manage configuration", icon: "Settings", action: () => setShowSettingsModal(true) },
            { label: "Generate Report", desc: "Synthesize final report", icon: "FileText", action: handleGenerateReport },
            { label: "Toggle Dark Mode", desc: `Switch to ${isDarkMode ? 'Light' : 'Dark'}`, icon: isDarkMode ? "Sun" : "Moon", action: () => setIsDarkMode(!isDarkMode) },
        ];

        // Ensure we have a valid standard selected before adding clause actions
        if (standardKey && allStandards[standardKey]) {
            const flatten = (list: Clause[]): Clause[] => list.reduce((acc, c) => {
                acc.push(c);
                if (c.subClauses) acc.push(...flatten(c.subClauses));
                return acc;
            }, [] as Clause[]);

            const allClauses = flatten(allStandards[standardKey].groups.flatMap(g => g.clauses));

            const clauseActions = allClauses.map(c => ({
                label: `[${c.code}] ${c.title}`,
                desc: c.description || "No description",
                icon: "Session6_Zap", // Use a generic icon or specific if available
                type: 'clause',
                // Action to select/deselect the clause
                action: () => {
                    const isSelected = selectedClauses.includes(c.id);
                    if (isSelected) setSelectedClauses(prev => prev.filter(id => id !== c.id));
                    else setSelectedClauses(prev => [...prev, c.id]);
                    insertTextAtCursor(`[${c.code}] ${c.title}`);
                    setToastMsg(`Inserted clause ${c.code} and ${isSelected ? 'removed from' : 'added to'} audit scope.`);
                    setIsCmdPaletteOpen(false);
                },
                // Action strictly for looking up reference
                onReference: (e: any) => {
                    if (e) e.stopPropagation();
                    handleOpenReferenceClause(c);
                    setIsCmdPaletteOpen(false);
                }
            }));
            return [...baseActions, ...clauseActions];
        }

        return baseActions;
    }, [isDarkMode, standardKey, allStandards, selectedClauses, activeKeyId, apiKeys]); 

    // ... (Badge, Tooltip, and Render logic - kept same) ...
    const displayBadge = useMemo(() => {
        const currentStandardName = allStandards[standardKey]?.name || "";
        const match = currentStandardName.match(/\((.*?)\)/);
        return match ? match[1] : (currentStandardName.split(' ')[0] || 'ISO');
    }, [standardKey, allStandards]);

    const badgeColorClass = useMemo(() => {
        const text = displayBadge.toUpperCase();
        if (text.includes('EMS') || text.includes('14001')) return "bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-700/50";
        if (text.includes('QMS') || text.includes('9001')) return "bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 border-blue-200 dark:border-blue-700/50";
        if (text.includes('ISMS') || text.includes('27001')) return "bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300 border-purple-200 dark:border-purple-700/50";
        return "bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 border-indigo-100 dark:border-indigo-800/50";
    }, [displayBadge]);

    const getAnalyzeTooltip = () => {
        if (isAnalyzeLoading) return "AI is analyzing...";
        const missing = [];
        if (selectedClauses.length === 0) missing.push("Clauses");
        if (!hasEvidence) missing.push("Evidence");
        return missing.length > 0 ? `Missing: ${missing.join(" & ")}` : "Click to Start AI Analysis";
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 ease-soft relative">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}

            {aiError && (
                <div className={`fixed z-[9999] top-20 left-4 right-4 md:left-auto md:right-5 md:w-96 md:max-w-sm bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl rounded-r-xl p-4 animate-shake transition-all duration-300 ${isErrorClosing ? 'opacity-0 translate-x-4' : 'opacity-100 translate-x-0'}`}>
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold"><Icon name="AlertCircle" size={20}/><span>System Alert</span></div>
                        <button onClick={dismissError} className="text-gray-400 hover:text-slate-800 dark:hover:text-white transition-colors p-1 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700"><Icon name="X" size={18}/></button>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed mt-1">{aiError}</p>
                </div>
            )}

            <header className="flex-shrink-0 px-4 md:px-6 py-0 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-[70] relative flex justify-between items-center h-16 transition-all duration-300">
                <div className="flex items-center h-full gap-3 md:gap-5">
                    <div className="relative group cursor-pointer flex items-center justify-center transition-all duration-500 hover:opacity-100 active:scale-95" onClick={() => setIsSidebarOpen(!isSidebarOpen)} title="Toggle Sidebar">
